    even
IsrNmi:
    move.b  ($00FF,A4),D0
    moveq   #0,D2
    move.b  ($005C,A4),D2
    beq  _anon_z07_0
    eori.b #$02,D0
_anon_z07_0:
    clr.b   ($005C,A4)  ; PATCH P3: clear NMI NT toggle request flag
    andi.b #$7F,D0
    move.b  D0,($00FF,A4)
    andi.b #$7E,D0
    jsr     _ppu_write_0  ; PPU $2000 write, D0=val
    ; Set PPUMASK.
    ; Start with curren mask value, but ...
    move.b  ($00FE,A4),D0
    moveq   #0,D3
    move.b  ($00E3,A4),D3
    bne  _L_z07_IsrNmi_EnableAllVideo
    moveq   #0,D3
    move.b  ($0014,A4),D3
    bne  _L_z07_IsrNmi_SetPpuMask
    moveq   #0,D3
    move.b  ($0017,A4),D3
    bne  _L_z07_IsrNmi_SetPpuMask
    even
_L_z07_IsrNmi_EnableAllVideo:
    ori.b #$1E,D0
    even
_L_z07_IsrNmi_SetPpuMask:
    jsr     _ppu_write_1  ; PPU $2001 write, D0=val
    move.b  D0,($00FE,A4)
    ; Copy all our sprites to OAM.
    ;
    moveq   #0,D0
    jsr     _ppu_write_3  ; PPU $2003 write, D0=val
    moveq   #2,D0
    jsr     _oam_dma         ; $4014 OAM DMA, D0=page
    ; Reset scroll register.
    ;
    moveq   #0,D0
    jsr     _ppu_write_5  ; PPU $2005 write, D0=val
    jsr     _ppu_write_5  ; PPU $2005 write, D0=val
    moveq   #6,D0
    jsr     SwitchBank
    jsr     TransferCurTileBuf
    ; Reset PPUADDR.
    ; I believe that the write of $3F00 is unneeded.
    moveq   #63,D0
    jsr     _ppu_write_6  ; PPU $2006 write, D0=val
    moveq   #0,D0
    jsr     _ppu_write_6  ; PPU $2006 write, D0=val
    jsr     _ppu_write_6  ; PPU $2006 write, D0=val
    jsr     _ppu_write_6  ; PPU $2006 write, D0=val
    even
_L_z07_IsrNmi_WaitVBlankEnd:
    ; If Sprite 0 Hit is set,
    ; then wait for it to be cleared by the ending of VBLANK.
    ;
    jsr     _ppu_read_2  ; PPU $2002 read → D0
    andi.b #$40,D0
    bne  _L_z07_IsrNmi_WaitVBlankEnd
    jsr     _ppu_read_2  ; PPU $2002 read → D0
    ; Wait for Sprite 0 hit, if needed.
    ;
    move.b  ($00E3,A4),D0
    beq  _L_z07_IsrNmi_CheckScroll
    moveq   #5,D0
    jsr     SwitchBank
    jsr     WaitAndScrollToSplitBottom
    even
_L_z07_IsrNmi_CheckScroll:
    ; If updating a game mode instead of initializing one,
    ; then simply scroll for game modes 0, 5, 9, $B, $C, $13.
    move.b  ($0011,A4),D0
    beq  _L_z07_IsrNmi_UpdateTimers
    move.b  ($0012,A4),D0
    beq  _L_z07_IsrNmi_SetScroll
    cmpi.b  #$05,D0
    beq  _L_z07_IsrNmi_SetScroll
    cmpi.b  #$09,D0
    beq  _L_z07_IsrNmi_SetScroll
    cmpi.b  #$0B,D0
    beq  _L_z07_IsrNmi_SetScroll
    cmpi.b  #$0C,D0
    beq  _L_z07_IsrNmi_SetScroll
    cmpi.b  #$13,D0
    bne  _L_z07_IsrNmi_UpdateTimers
    even
_L_z07_IsrNmi_SetScroll:
    jsr     _ppu_read_2  ; PPU $2002 read → D0
    move.b  ($00FD,A4),D0
    jsr     _ppu_write_5  ; PPU $2005 write, D0=val
    move.b  ($00FC,A4),D0
    jsr     _ppu_write_5  ; PPU $2005 write, D0=val
    move.b  ($00FF,A4),D0
    jsr     _ppu_write_0  ; PPU $2000 write, D0=val
    jsr     _apply_genesis_scroll  ; Apply scroll shadows to VDP VSRAM/H-scroll
    even
_L_z07_IsrNmi_UpdateTimers:
    ; If paused or in menu, then don't decrement timers.
    ;
    move.b  ($00E1,A4),D0
    move.b  ($00E0,A4),D1
    or.b  D1,D0
    bne  _L_z07_IsrNmi_CheckInput
    moveq   #38,D2
    moveq   #60,D0
    moveq   #78,D3
    move.b  D2,($0000,A4)
    subq.b  #1,($00,A4,D2.W)
    bpl  _L_z07_IsrNmi_DecTimers
    moveq   #9,D0
    move.b  D0,($00,A4,D2.W)
    move.b  D3,D0
    even
_L_z07_IsrNmi_DecTimers:
    moveq   #0,D2
    move.b  D0,D2
    even
_L_z07_IsrNmi_LoopTimer:
    move.b  ($00,A4,D2.W),D0
    beq  _anon_z07_1
    subq.b  #1,($00,A4,D2.W)
_anon_z07_1:
    subq.b  #1,D2
    move.b  ($0000,A4),D1
    cmp.b   D1,D2
    bne  _L_z07_IsrNmi_LoopTimer
    even
_L_z07_IsrNmi_CheckInput:
    ; Sprite 0 is used for scrolling. Input isn't checked while scrolling.
    ;
    move.b  ($00E3,A4),D0
    bne  _L_z07_IsrNmi_ScrambleRandom
    jsr     ReadInputs
    even
_L_z07_IsrNmi_ScrambleRandom:
    moveq   #24,D2
    moveq   #13,D3
    move.b  ($00,A4,D2.W),D0
    andi.b #$02,D0
    move.b  D0,($0000,A4)
    move.b  ($01,A4,D2.W),D0
    andi.b #$02,D0
    move.b  ($0000,A4),D1
    eor.b  D1,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    beq  _L_z07_IsrNmi_LoopRandom
    ori     #$11,CCR  ; SEC: set C+X
    even
_L_z07_IsrNmi_LoopRandom:
    move.b  ($00,A4,D2.W),D1
    roxr.b  #1,D1   ; ROR $00,X
    scs     D6             ; P4: save C (= rotated-out bit) *before* move clears it
    move.b  D1,($00,A4,D2.W)
    addq.b  #1,D2
    subq.b  #1,D3
    add.b   D6,D6          ; P4: restore X from D6 ($FF -> X=1, $00 -> X=0)
    tst.b   D3             ; P4: re-set Z for loop branch
    bne  _L_z07_IsrNmi_LoopRandom
    moveq   #0,D0
    jsr     SwitchBank
    jsr     DriveAudio
    addq.b  #1,($0015,A4)
    move.b  ($0011,A4),D0
    bne  _L_z07_IsrNmi_Update
    jsr     InitializeGameOrMode
    jmp     _L_z07_IsrNmi_EnableNMI

    even
_L_z07_IsrNmi_Update:
    jsr     UpdateMode
    even
_L_z07_IsrNmi_EnableNMI:
    jsr     _ppu_read_2  ; PPU $2002 read → D0
    move.b  ($00FF,A4),D0
    ori.b #$80,D0
    jsr     _ppu_write_0  ; PPU $2000 write, D0=val
    move.b  D0,($00FF,A4)
    jsr     _apply_genesis_scroll  ; P2: re-apply scroll after game logic
    rts   ; RTI → RTS (IsrNmi is a subroutine; VBlankISR handles the RTE)

    even
ResetPpuRegisters:
    moveq   #0,D0
    jsr     _ppu_write_5  ; PPU $2005 write, D0=val
    move.b  D0,($00FD,A4)
    jsr     _ppu_write_5  ; PPU $2005 write, D0=val
    move.b  D0,($00FC,A4)
    moveq   #48,D0
    jsr     _ppu_write_0  ; PPU $2000 write, D0=val
    move.b  D0,($00FF,A4)
