TableJump:
    lsl.b  #1,D0   ; ASL A
    moveq   #0,D3
    move.b  D0,D3
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($0000,A4)
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($0001,A4)
    addq.b  #1,D3
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    move.b  D0,($0002,A4)
    addq.b  #1,D3
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    move.b  D0,($0003,A4)
    move.w  ($0002,A4),D1  ; JMP ($nnnn) ptr lo
    ext.l   D1
    add.l   #NES_RAM,D1
    movea.l D1,A0
    jmp     (A0)              ; JMP ($0002)

    even
HideAllSprites:
    moveq   #0,D3
    moveq   #64,D2
