_L_z07_HideAllSprites_Loop:
    move.b  #$F8,D0
    lea     ($0200,A4),A0
    move.b  D0,(A0,D3.W)
    addq.b  #1,D3
    addq.b  #1,D3
    addq.b  #1,D3
    addq.b  #1,D3
    subq.b  #1,D2
    bne  _L_z07_HideAllSprites_Loop
    rts

; Params:
; A: high byte of high address to reset
; Y: low byte of high address to reset
;
; Resets all bytes from $300 to byte Y of page A.
;
    even
ClearRam0300UpTo:
    move.b  D0,($0001,A4)
    moveq   #0,D0
    move.b  D0,($0000,A4)
    even
_L_z07_ClearRam0300UpTo_Loop:
    moveq   #0,D0
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    subq.b  #1,D3
    cmpi.b  #$FF,D3
    bne  _L_z07_ClearRam0300UpTo_Loop
    subq.b  #1,($0001,A4)
    move.b  ($0001,A4),D0
    cmpi.b  #$03,D0
    bcc  _L_z07_ClearRam0300UpTo_Loop
    ; We overwrote the dynamic transfer buf with zeroes.
    ; But the cleared state of the tile buf has the end marker at
    ; the beginning. Write the end marker.
    move.b  #$FF,D0
    move.b  D0,($0302,A4)
    eori    #$01,CCR  ; normalize C to 6502 polarity before RTS
    rts

