ReadInputs:
    moveq   #1,D0
    jsr     _ctrl_strobe     ; $4016 controller strobe
    moveq   #0,D0
    jsr     _ctrl_strobe     ; $4016 controller strobe
    move.b  D0,($0003,A4)
    move.b  D0,($0004,A4)
    moveq   #0,D2
    move.b  D0,D2
    jsr     ReadOneController
    addq.b  #1,D2
    even
ReadOneController:
    ; Read over and over until you get 
    ; two of the same readings in a row
    ; (three from the very beginning).
    ; [02] : previous reading in this loop
    ; [03]/2 : successive matching readings (for each controller)
    ;
    move.b  D0,($0002,A4)
    moveq   #1,D0
    jsr     _ctrl_strobe     ; $4016 controller strobe
    moveq   #0,D0
    jsr     _ctrl_strobe     ; $4016 controller strobe
    moveq   #8,D3
    even
_L_z07_ReadOneController_Read:
    jsr     _ctrl_read_1    ; $4016 controller 1 → D0
    lsr.b  #1,D0   ; LSR A
    lea     ($00F8,A4),A0
    move.b  (A0,D2.W),D1
    roxl.b  #1,D1   ; ROL ButtonsPressed,X
    move.b  D1,(A0,D2.W)
    lsr.b  #1,D0   ; LSR A
    move.b  ($0000,A4),D1
    roxl.b  #1,D1   ; ROL $00
    move.b  D1,($0000,A4)
    subq.b  #1,D3
    bne  _L_z07_ReadOneController_Read
    lea     ($00F8,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0002,A4),D1
    cmp.b   D1,D0
    beq.s  __far_z_07_0000
    jmp  ReadOneController
__far_z_07_0000:
    addq.b  #1,($03,A4,D2.W)
    moveq   #0,D3
    move.b  ($03,A4,D2.W),D3
    cmpi.b  #$02,D3
    bcc.s  __far_z_07_0001
    jmp  ReadOneController
__far_z_07_0001:
    move.b  ($0000,A4),D0
    lea     ($00F8,A4),A0
    move.b  (A0,D2.W),D1
    or.b  D1,D0
    lea     ($00F8,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D0,-(A5)  ; PHA
    lea     ($00FA,A4),A0
    move.b  (A0,D2.W),D1
    eor.b  D1,D0
    lea     ($00F8,A4),A0
    move.b  (A0,D2.W),D1
    and.b  D1,D0
    lea     ($00F8,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  (A5)+,D0  ; PLA
    lea     ($00FA,A4),A0
    move.b  D0,(A0,D2.W)
