    ; If the item was taken, or it wasn't active, then return.
    ;
    jsr     GetRoomFlagUWItemState
    bne  _anon_z07_3
    move.b  ($00BF,A4),D0
    bmi  _anon_z07_3
    ; If the item type is "none" ($3F), then return.
    ;
    move.b  ($00AB,A4),D0
    cmpi.b  #$3F,D0
    beq  _anon_z07_3
