__far_z_07_0007:
    cmpi.b  #$30,D0
    bne.s  __far_z_07_0008
    jmp  AnimateRoomItemOnMonster
__far_z_07_0008:
    ; A monster is not carrying the item. So draw the item as usual.
    ;
    ;
    ; Room item is in object slot $13.
    moveq   #19,D2
