AnimateItemObject:
    move.b  D0,-(A5)  ; PHA
    ; If the lifetime timer of the item >= $F0 and even, then
    ; return without drawing. This makes it flash at first.
    ;
    ; [03A8][X] is used to count down the life of the item.
    ;
    lea     ($03A8,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$F0,D0
