    ; Store the item value part of it in [04].
    ;
    ;
    ; Restore the item ID.
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    lea     (ItemIdToDescriptor).l,A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$30,D0
    beq  _L_z07_AnimateItemObject_SetItemValueFF
    andi.b #$0F,D0
    even
_L_z07_AnimateItemObject_SetItemValue:
    move.b  D0,($0004,A4)
    ; Get item slot for the item ID, and draw the item.
    ;
    lea     (ItemIdToSlot).l,A0
    move.b  (A0,D2.W),D0
    moveq   #0,D2
    move.b  D0,D2
    moveq   #0,D3
    move.b  D0,D3
    jmp     DrawItemBySlot

    even
_L_z07_AnimateItemObject_SetItemValueFF:
    move.b  #$FF,D0
    bne  _L_z07_AnimateItemObject_SetItemValue
; Params:
; X: item slot
; Y: item slot
; [00]: X
; [01]: Y
;
    even
DrawItemInInventory:
    lea     ($0657,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0004,A4)
; Params:
; X: item slot
; Y: item slot
; [00]: X
; [01]: Y
; [04]: item value / sprite palette row attribute
;
    even
DrawItemBySlot:
    lea     (ItemSlotToPaletteOffsetsOrValues).l,A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$16,D2
    beq  _L_z07_DrawItemBySlot_Flash
    cmpi.b  #$1A,D2
    beq  _L_z07_DrawItemBySlot_Flash
    cmpi.b  #$1B,D2
    beq  _L_z07_DrawItemBySlot_Flash
    cmpi.b  #$19,D2
    bne  _L_z07_DrawItemBySlot_VariesByColor
    even
_L_z07_DrawItemBySlot_Flash:
    move.b  ($0015,A4),D0
    andi.b #$08,D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    even
_L_z07_DrawItemBySlot_VariesByColor:
    cmpi.b  #$00,D2
    beq  _L_z07_DrawItemBySlot_AddItemAndTableValue
    cmpi.b  #$04,D2
    beq  _L_z07_DrawItemBySlot_AddItemAndTableValue
    cmpi.b  #$02,D2
    beq  _L_z07_DrawItemBySlot_AddItemAndTableValue
    cmpi.b  #$07,D2
    beq  _L_z07_DrawItemBySlot_AddItemAndTableValue
    cmpi.b  #$0B,D2
    beq  _L_z07_DrawItemBySlot_AddItemAndTableValue
    even
_L_z07_DrawItemBySlot_WriteSprites:
    ; We got here in one of three ways:
    ;
    ; A. The item flashes. Attribute value 1 or 2 was chosen
    ;    explicitly.
    ; B. The item color varies. ItemSlotToPaletteOffsetsOrValues
    ;    held an offset that was added to base palette attribute
    ;    passed in [$04]. This corresponds to class 2 items.
    ; C. Item doesn't change color. ItemSlotToPaletteOffsetsOrValues
    ;    held absolute attributes.
    ;
    ; At this point, A holds the final sprite attributes.
    moveq   #0,D2
    move.b  D2,($000C,A4)
    moveq   #15,D2
    ; Write sprites.
    ; A holds the calculated sprite attributes.
    ; Y holds the item slot.
    jmp     Anim_WriteStaticItemSpritesWithAttributes

    even
_L_z07_DrawItemBySlot_AddItemAndTableValue:
    ; Calculate sprite attributes by adding item value / sprite palette
    ; row attribute and the element from ItemSlotToPaletteOffsetsOrValues,
    ; which here represents an offset from the palette row.
    ;
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0004,A4),D1
    addx.b  D1,D0   ; ADC $04
    cmpi.b  #$00,D2
    bne  _L_z07_DrawItemBySlot_WriteSprites
    cmpi.b  #$02,D0
    bne  _L_z07_DrawItemBySlot_WriteSprites
    moveq   #32,D3
    jmp     _L_z07_DrawItemBySlot_WriteSprites

    even
DrawStatusBarPotion:
    ; We have a potion to draw.
    ;
    ;
    ; Potion item slot.
    moveq   #7,D2
    move.b  D2,($0656,A4)
    beq.s  __far_z_07_0010
    jmp  DrawStatusBarItemB
__far_z_07_0010:
    even
DrawStatusBarItemsAndEnsureItemSelected:
    ; Draws the selected item and the sword in the status bar.
    ; Before drawing the item, it ensures that SelectedItemSlot
    ; refers to an occupied, equippable item slot.
    ;
    ; This accounts for the fallback behavior between potions
    ; and letters and the two boomerangs.
    ;
    ; Start at slot zero. Normally, it would be used to
    ; check swords. When it's used as the selected item index;
    ; it's a pseudo-slot used for checking boomerangs.
    ;
    moveq   #0,D2
    move.b  ($0656,A4),D2
    bne.s  __far_z_07_0011
    jmp  DrawStatusBarBoomerang
__far_z_07_0011:
    lea     ($0657,A4),A0
    move.b  (A0,D2.W),D0
    bne.s  __far_z_07_0012
    jmp  CheckMissingItem
__far_z_07_0012:
    cmpi.b  #$0F,D2
    beq.s  __far_z_07_0013
    jmp  DrawStatusBarItemB
__far_z_07_0013:
    moveq   #0,D3
    move.b  ($065E,A4),D3
    beq.s  __far_z_07_0014
    jmp  DrawStatusBarPotion
__far_z_07_0014:
    lsr.b  #1,D0   ; LSR A
    ori.b #$01,D0
    even
DrawStatusBarItemB:
    move.b  D0,($0004,A4)
    moveq   #31,D0
    move.b  D0,($0001,A4)
    moveq   #124,D0
    move.b  D0,($0000,A4)
    moveq   #5,D0
    jsr     SwitchBank
    jsr     DrawItemInInventoryWithX
    jmp     DrawStatusBarSword

    even
DrawStatusBarBoomerang:
    moveq   #30,D2
    even
_L_z07_DrawStatusBarBoomerang_LoopBoomerang:
    lea     ($0657,A4),A0
    move.b  (A0,D2.W),D0
    beq.s  __far_z_07_0015
    jmp  DrawStatusBarItemB
__far_z_07_0015:
    subq.b  #1,D2
    cmpi.b  #$1C,D2
    bne  _L_z07_DrawStatusBarBoomerang_LoopBoomerang
    moveq   #0,D2
    jmp     EnsureSelectedItem

    even
FindItemOrDrawSword:
    lea     ($0657,A4),A0
    move.b  (A0,D2.W),D0
    ; If there's an item in this slot, then SelectedItemSlot was already
    ; set. Go handle the sword instead of drawing the item.
    ; Next frame, we'll draw this item.
    beq.s  __far_z_07_0016
    jmp  DrawStatusBarSword
__far_z_07_0016:
    even
EnsureSelectedItem:
    move.b  D2,D0
    moveq   #0,D3
    move.b  D0,D3
    moveq   #5,D0
    jsr     SwitchBank
    moveq   #2,D0
    jsr     FindAndSelectOccupiedItemSlot
    even
DrawStatusBarSword:
    ; Handle the sword.
    ;
    moveq   #0,D2
    lea     ($0657,A4),A0
    move.b  (A0,D2.W),D0
    bne.s  __far_z_07_0017
    jmp  L1E847_Exit
__far_z_07_0017:
    moveq   #31,D0
    move.b  D0,($0001,A4)
    move.b  #$94,D0
    move.b  D0,($0000,A4)
    moveq   #5,D0
    jsr     SwitchBank
    jmp     DrawItemInInventoryWithX

    even
CheckMissingItem:
    ; No item in slot.
    ;
    cmpi.b  #$07,D2
    beq.s  __far_z_07_0018
    jmp  FindItemOrDrawSword
__far_z_07_0018:
    move.b  ($0666,A4),D0
    bne.s  __far_z_07_0019
    jmp  EnsureSelectedItem
__far_z_07_0019:
    moveq   #15,D2
    move.b  D2,($0656,A4)
    beq.s  __far_z_07_0020
    jmp  FindItemOrDrawSword
__far_z_07_0020:
    even
CheckLiftItem:
    move.b  ($0505,A4),D0
    bne.s  __far_z_07_0021
    jmp  L1E859_Exit
__far_z_07_0021:
    subq.b  #1,($0506,A4)
    bne.s  __far_z_07_0022
    jmp  EndLinkLiftingItem
__far_z_07_0022:
    ; Set player state to halted.
    ;
    moveq   #64,D0
    move.b  D0,($00AC,A4)
; Params:
; [0505]: item type
;
;
; Set item X the same as Link's.
    even
SetUpAndDrawLinkLiftingItem:
    move.b  ($0070,A4),D0
    move.b  D0,($0083,A4)
    move.b  ($0084,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$10,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$10
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($0097,A4)
; Params:
; [0505]: item type
;
;
; We're dealing with Link object.
    even
DrawLinkLiftingItem:
    moveq   #0,D2
    jsr     Anim_FetchObjPosForSpriteDescriptor
    jsr     Anim_SetSpriteDescriptorAttributes
    move.b  D0,($000C,A4)
    moveq   #72,D0
    move.b  D0,($0343,A4)
    moveq   #76,D0
    move.b  D0,($0344,A4)
    moveq   #33,D3
    jsr     Anim_WriteSpecificItemSprites
    addq.b  #1,($0504,A4)
    move.b  ($0505,A4),D0
    moveq   #19,D2
    jsr     AnimateItemObject
    subq.b  #1,($0504,A4)
    move.b  ($0052,A4),D0
    bne.s  __far_z_07_0023
    jmp  L1E847_Exit
__far_z_07_0023:
    ; Then lift with one hand.
    ; Change the right side to a tile without the arm raised.
    moveq   #8,D0
    move.b  D0,($024D,A4)
    even
L1E847_Exit:
    rts

    even
EndLinkLiftingItem:
    ; Make Link idle, and reset the item type.
    ;
    moveq   #0,D0
    move.b  D0,($00AC,A4)
    move.b  D0,($0505,A4)
    ; If in UW, play the level's song again.
    ;
    moveq   #0,D3
    move.b  ($0010,A4),D3
    bne.s  __far_z_07_0024
    jmp  L1E859_Exit
__far_z_07_0024:
    lea     (LevelSongIds).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0600,A4)
    even
L1E859_Exit:
    rts

; Returns:
; A: unique room ID
; Y: room ID
;
    even
GetUniqueRoomId:
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    lea     (NES_SRAM+$09FE).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$3F,D0
    rts

; Params:
; A: first tile
; X: object index
; [F7]: not 0 to switch to bank 4 before returning
;
;
; First, cue the transfer of the 4 tiles to nametable 0.
;
; [05] holds the first tile.
    even
ChangeTileObjTiles:
    move.b  D0,($0005,A4)
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    move.b  ($70,A4,D2.W),D0
    move.b  D0,($0003,A4)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0002,A4)
    jsr     MapScreenPosToPpuAddr
    moveq   #0,D2
    move.b  ($0301,A4),D2
    ; Two transfer records will be written to the buffer and an end marker.
    ;
    ; Each record is 5 bytes and will transfer 2 tiles arranged vertically.
    ; In total, 11 bytes will be written.
    ;
    ; First, write the high byte of PPU address in each record.
    ;
    move.b  ($0000,A4),D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0307,A4),A0
    move.b  D0,(A0,D2.W)
    ; Write the low address in the first record. In the second record,
    ; write (low address + 1).
    ;
    move.b  ($0001,A4),D0
    lea     ($0303,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0308,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0308,A4),A0
    addq.b  #1,(A0,D2.W)
    ; Write the first tile twice in each record. Patch them later.
    ;
    move.b  ($0005,A4),D0
    lea     ($0305,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0306,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($030A,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($030B,A4),A0
    move.b  D0,(A0,D2.W)
    ; If tile >= $46 and < $F3, add 2 to the tile bytes in the second record.
    ; Add 1 more to the second byte in each record.
    ; Here is an example result of this manipulation:
    ;   record 1: $70, $71
    ;   record 2: $72, $73
    ;
    cmpi.b  #$46,D0
    bcs  _L_z07_ChangeTileObjTiles_SetCountBytes
    cmpi.b  #$F3,D0
    bcc  _L_z07_ChangeTileObjTiles_SetCountBytes
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$02,D1
    addx.b  D1,D0   ; ADC #$02 (X flag = 6502 C)
    lea     ($030A,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($030B,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0306,A4),A0
    addq.b  #1,(A0,D2.W)
    lea     ($030B,A4),A0
    addq.b  #1,(A0,D2.W)
    even
_L_z07_ChangeTileObjTiles_SetCountBytes:
    ; Set the count byte in each record to $82:
    ; 2 tiles arranged vertically
    ;
    move.b  #$82,D0
    lea     ($0304,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0309,A4),A0
    move.b  D0,(A0,D2.W)
    ; Write the end marker.
    ;
    move.b  #$FF,D0
    lea     ($030C,A4),A0
    move.b  D0,(A0,D2.W)
    ; Update dynamic buffer length with 10 new bytes.
    ;
    move.b  D2,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$0A,D1
    addx.b  D1,D0   ; ADC #$0A (X flag = 6502 C)
    move.b  D0,($0301,A4)
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    moveq   #5,D0
    jsr     SwitchBank
    ; Change the tiles in the play area map.
    ;
    jsr     ChangePlayMapSquareOW
    ; TODO: ?
    ; If [F7] is set, switch to bank 4, and reset [F7].
    ;
    move.b  ($00F7,A4),D0
    beq  _anon_z07_5
    moveq   #4,D0
    jsr     SwitchBank
_anon_z07_5:
    moveq   #0,D0
    move.b  D0,($00F7,A4)
    rts

; Params:
; [$0A]: tile
;
    even
FillTileMap:
    moveq   #5,D0
    jsr     SwitchBank
    jsr     FetchTileMapAddr
    moveq   #0,D3
    even
_L_z07_FillTileMap_Loop:
    move.b  ($000A,A4),D0
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    jsr     Add1ToInt16At0
    move.b  ($0000,A4),D0
    cmpi.b  #$F0,D0
    bne  _L_z07_FillTileMap_Loop
    move.b  ($0001,A4),D0
    cmpi.b  #$67,D0
    bne  _L_z07_FillTileMap_Loop
    eori    #$01,CCR  ; normalize C to 6502 polarity before RTS
    rts

; Unknown block
    dc.b    $FF, $FF

    even
InitializeGameOrMode:
    move.b  ($00F4,A4),D0
    beq.s  __far_z_07_0025
    jmp  InitMode
__far_z_07_0025:
    moveq   #1,D0
    jsr     SwitchBank
    jsr     CopyCommonCodeToRam
    moveq   #6,D0
    jsr     SwitchBank
    jsr     CopyCommonDataToRam
    moveq   #90,D0
    move.b  D0,(NES_SRAM+$0001).l
    move.b  #$A5,D0
    move.b  D0,(NES_SRAM+$1FFF).l
    addq.b  #1,($00F4,A4)
    rts

    even
InitMode:
    ifne DEBUG_TELEPORT
    jsr     _debug_teleport_check      ; PATCH P37: DPAD teleport (InitMode)
    tst.b   D0
    beq.s   _L_z07_InitMode_noTp
    rts
_L_z07_InitMode_noTp:
    endc
    moveq   #5,D0
