    dc.l    InitMode7   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    InitMode8   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    InitMode9   ; jump table entry (32-bit for _m68k_tablejump)
