    ; Clear level kill counts.
    ;
    moveq   #127,D3
    even
_L_z07_InitMode2_ClearCounts:
    lea     ($0560,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _L_z07_InitMode2_ClearCounts
