InitMode7:
    moveq   #5,D0
    jsr     SwitchBank
    jsr     InitMode7Submodes
    move.b  ($00E3,A4),D0
    beq  _L_z07_InitMode7_Exit
    ; After the last submode (5 or 6), sprite-0 check was enabled.
    ; So, set the appropriate mirroring for scrolling during mode update.
    ;
    ;
    ; TODO: [$F3] ?
    move.b  ($00F3,A4),D0
