BeginUpdateWorld:
    ; If we have the clock, then
    ; force the player's invincibility.
    move.b  ($066C,A4),D0
    beq  _L_z07_BeginUpdateWorld_NotInvincible
    move.b  ($04F0,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$10,D1
    addx.b  D1,D0   ; ADC #$10 (X flag = 6502 C)
    move.b  D0,($04F0,A4)
    even
_L_z07_BeginUpdateWorld_NotInvincible:
    ; Update the player.
    ;
    jsr     UpdatePlayer
    move.b  ($0011,A4),D0
    bne  _L_z07_BeginUpdateWorld_CheckChaseTarget
    jmp     _L_z07_BeginUpdateWorld_FinishUpdatePlay

    even
_L_z07_BeginUpdateWorld_CheckChaseTarget:
    ; If Link can be chased, then set his coordinates as the target.
    ;
    move.b  ($0060,A4),D0
    bne  _L_z07_BeginUpdateWorld_UpdateWeapons
    move.b  ($0070,A4),D0
    move.b  D0,($0061,A4)
    move.b  ($0084,A4),D0
    move.b  D0,($0062,A4)
    even
_L_z07_BeginUpdateWorld_UpdateWeapons:
    ; Update weapons and items.
    ;
    moveq   #13,D2
    jsr     UpdateSwordOrRod
    moveq   #14,D2
    jsr     UpdateSwordShotOrMagicShot
    moveq   #15,D2
    jsr     UpdateBoomerangOrFood
    moveq   #16,D2
    jsr     UpdateBombOrFire
    moveq   #17,D2
    jsr     UpdateBombOrFire
    moveq   #18,D2
    jsr     UpdateRodOrArrow
    ; If it's not time to change the chase target, then
    ; skip this and go update objects.
    ;
    move.b  ($004A,A4),D0
    bne  _L_z07_BeginUpdateWorld_LoopObject
    ; Set the chase long-timer to a random value between 0 and 7.
    ;
    move.b  ($0019,A4),D0
    andi.b #$07,D0
    move.b  D0,($004A,A4)
    ; Switch the flag indicating whether Link is the target.
    ; If the value is 0 (Link *is* the target), then
    ; skip this and go update objects.
    ;
    move.b  ($0060,A4),D0
    eori.b #$01,D0
    move.b  D0,($0060,A4)
    beq  _L_z07_BeginUpdateWorld_LoopObject
    ; If Link's X has not changed since the last frame
    ; (when Link was the target), then XOR the chase target
    ; coordinates (which were Link's coordinates last frame).
    ;
    ; This ends up reflecting Link's coordinates across the room;
    ; so that monsters chase away from him.
    ;
    ; But if Link's X has changed since the last frame, then
    ; leave the chase target coordinates with his old coordinates.
    ;
    move.b  ($0061,A4),D0
    move.b  ($0070,A4),D1
    cmp.b   D1,D0
    bne  _L_z07_BeginUpdateWorld_LoopObject
    eori.b #$FF,D0
    move.b  D0,($0061,A4)
    move.b  ($0062,A4),D0
    eori.b #$FF,D0
    move.b  D0,($0062,A4)
    even
_L_z07_BeginUpdateWorld_LoopObject:
    ; Update objects from $B to 1.
    ;
    moveq   #0,D2
    move.b  ($0340,A4),D2
    jsr     DecrementInvincibilityTimer
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z07_BeginUpdateWorld_NextObject
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    jsr     UpdateObject
    ; If the object is autonomous and not checking collisions itself,
    ; then see about checking collisions and drawing on its behalf.
    ;
    ; Else go loop again.
    ;
    moveq   #0,D2
    move.b  ($0340,A4),D2
    lea     ($0405,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z07_BeginUpdateWorld_NextObject
    lea     ($04BF,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$01,D0
    bne  _L_z07_BeginUpdateWorld_NextObject
    ; If no attribute 1, then it indicates not to skip drawing. So, animate and draw.
    ;
    lea     ($04BF,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$04,D0
    bne  _anon_z07_10
    jsr     AnimateAndDrawObjectWalking
_anon_z07_10:
    ; Either way, we'll check collisions.
    ;
    moveq   #0,D2
    move.b  ($0340,A4),D2
    jsr     CheckMonsterCollisions
    even
_L_z07_BeginUpdateWorld_NextObject:
    ; Bottom of the object update loop.
    ;
    subq.b  #1,($0340,A4)
    bne  _L_z07_BeginUpdateWorld_LoopObject
    ; Set the current object slot to what it should be when we
    ; begin updating objects again next frame: $B
    ; the last object slot for monsters and tile objects
    ;
    ; Before the first frame of mode 5, the current object slot variable
    ; was set to $B in 05:87B9 (InitMode_EnterRoom).
    ;
    ; This can also be called the last slot for dynamically allocated objects.
    ;
    moveq   #11,D0
    move.b  D0,($0340,A4)
    ; If full hearts = 0, then only a partial heart is left.
    ; So, turn on the "heart warning".
    ;
    move.b  ($066F,A4),D0
    andi.b #$0F,D0
    bne  _L_z07_BeginUpdateWorld_CheckUW
    move.b  ($0604,A4),D0
    ori.b #$40,D0
    move.b  D0,($0604,A4)
    even
_L_z07_BeginUpdateWorld_CheckUW:
    ; If in UW, check statues, doors, secrets, and the power triforce.
    ;
    move.b  ($0010,A4),D0
    beq  _L_z07_BeginUpdateWorld_CheckOW
    moveq   #4,D0
    jsr     SwitchBank
    jsr     UpdateStatues
    jsr     UpdateTriforcePositionMarker
    moveq   #5,D0
    jsr     SwitchBank
    jsr     CheckUnderworldSecrets
    jsr     CheckShutters
    jsr     UpdateDoors
    moveq   #1,D0
    jsr     SwitchBank
    jsr     CheckPowerTriforceFanfare
    jmp     _L_z07_BeginUpdateWorld_TransferStatusBarMap

    even
_L_z07_BeginUpdateWorld_CheckOW:
    ; In OW.
    ; If game mode = 5, turn on sea sound effect if the room's
    ; attributes call for it.
    ;
    move.b  ($0012,A4),D0
    cmpi.b  #$05,D0
    bne  _L_z07_BeginUpdateWorld_CheckZora
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    lea     (NES_SRAM+$087E).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$04,D0
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    jsr     PlayEffect
    even
_L_z07_BeginUpdateWorld_CheckZora:
    ; In OW, make a zora, if applicable.
    ;
    moveq   #4,D0
    jsr     SwitchBank
    jsr     CheckZora
    even
_L_z07_BeginUpdateWorld_TransferStatusBarMap:
    ; If there are tiles or palettes in the dynamic transfer buf, then
    ; do not handle the status bar map trigger.
    ;
    move.b  ($0301,A4),D0
    bne  _L_z07_BeginUpdateWorld_FinishUpdatePlay
    ; Transfer the level's status bar map, if we got the signal.
    ;
    move.b  ($04E5,A4),D0
    beq  _L_z07_BeginUpdateWorld_FinishUpdatePlay
    moveq   #0,D0
    move.b  D0,($04E5,A4)
    moveq   #68,D0
    move.b  D0,($0014,A4)
    even
_L_z07_BeginUpdateWorld_FinishUpdatePlay:
    ; These actions are done after Link is updated, regardless
    ; of whether other objects were updated.
    ;
    jsr     CheckLiftItem
    jsr     MoveAndDrawRoomItem
    jsr     TryTakeRoomItem
    jsr     DrawStatusBarItemsAndEnsureItemSelected
    even
UpdateHeartsAndRupees:
    moveq   #5,D0
    jsr     SwitchBank
    jsr     World_FillHearts
    jmp     World_ChangeRupees

; Unknown block
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF, $FF, $FF, $FF

    even
UpdatePlayer:
    moveq   #0,D2
    jsr     DecrementInvincibilityTimer
    ; If Link is halted, then return.
    ;
    move.b  ($00AC,A4),D0
    andi.b #$C0,D0
    cmpi.b  #$40,D0
    bne.s  __far_z_07_0038
    jmp  L1EDEA_Exit
__far_z_07_0038:
    ; TODO:
    ;
    ; If Link is paralyzed (by a like-like), then
    ; reset input direction.
    ;
    ; As far as I can tell, ObjInputDir could have been set to 0,
    ; instead of masking with $F0 for the same effect.
    ;
    move.b  ($0512,A4),D0
    beq  _anon_z07_11
    move.b  ($03F8,A4),D0
    andi.b #$F0,D0
    move.b  D0,($03F8,A4)
_anon_z07_11:
    moveq   #5,D0
    jsr     SwitchBank
    jsr     Link_HandleInput
    jsr     Walker_Move
    ifne TURBO_LINK
    jsr     _turbo_link_boost   ; PATCH P39: turbo Link speed boost
    endc
    even
Link_EndMoveAndAnimateInRoom:
    move.b  ($0012,A4),D0
    cmpi.b  #$0A,D0
    bne.s  __far_z_07_0039
    jmp  L1EDEA_Exit
__far_z_07_0039:
    jsr     Link_EndMoveAndAnimate
    move.b  ($0010,A4),D0
    beq  _L_z07_Link_EndMoveAndAnimateInRoom_Exit
    jsr     ShowLinkSpritesBehindHorizontalDoors
    even
_L_z07_Link_EndMoveAndAnimateInRoom_Exit:
    moveq   #0,D2
; Params:
; X: 0
;
; Ensure that, if grid offset = 0, then X is a multiple of 8,
; and Y is (multiple of 8) OR 5. For example, ($30, $7D) or ($58, $B5).
;
    even
EnsureObjectAligned:
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    beq.s  __far_z_07_0040
    jmp  L1EDEA_Exit
__far_z_07_0040:
    move.b  ($70,A4,D2.W),D0
    andi.b #$F8,D0
    move.b  D0,($70,A4,D2.W)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$F8,D0
    ori.b #$05,D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    even
L1EDEA_Exit:
    rts

    even
WalkableTiles:
    dc.b    $8D, $91, $9C, $AC, $AD, $CC, $D2, $D5
    dc.b    $DF

; Params:
; X: object index
;
; Returns:
; A: tile
; [049E][X]: tile
;
    even
GetCollidableTileStill:
    moveq   #0,D3
    move.b  D3,($000F,A4)
    bne.s  __far_z_07_0041
    jmp  GetCollidableTile
__far_z_07_0041:
; Params:
; X: object index
; [0F]: direction
;
; Returns:
; A: tile
; [049E][X]: tile
;
;
; Use -8 ($F8) for the hotspot offset, if it's Link.
    even
GetCollidingTileMoving:
    move.b  #$F8,D3
    cmpi.b  #$00,D2
    beq  _anon_z07_12
    move.b  #$F0,D3
_anon_z07_12:
    ; If direction is up, left, or 0,
    ; then use the offset we determined above.
    move.b  ($000F,A4),D0
    andi.b #$05,D0
    bne.s  __far_z_07_0042
    jmp  GetCollidableTile
__far_z_07_0042:
    ; Else if it's down,
    ; then use offset 8.
    moveq   #8,D3
    andi.b #$04,D0
    beq.s  __far_z_07_0043
    jmp  GetCollidableTile
__far_z_07_0043:
    ; For right, use offset $10.
    ;
    moveq   #16,D3
; Params:
; X: object index
; Y: offset from hotspot
; [0F]: direction or 0
;
; Returns:
; A: tile
; [049E][X]: tile
;
    even
GetCollidableTile:
    move.b  D3,($0004,A4)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$0B,D1
    addx.b  D1,D0   ; ADC #$0B (X flag = 6502 C)
    moveq   #0,D3
    move.b  D0,D3
    move.b  D0,-(A5)  ; PHA
    move.b  ($000F,A4),D0
    andi.b #$0C,D0
    beq  _L_z07_GetCollidableTile_AdjustX
    andi.b #$04,D0
    beq  _L_z07_GetCollidableTile_AdjustY
    cmpi.b  #$DD,D3
    bcc  _L_z07_GetCollidableTile_AsIsX
    even
_L_z07_GetCollidableTile_AdjustY:
    move.b  (A5)+,D0  ; PLA
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0004,A4),D1
    addx.b  D1,D0   ; ADC $04
    move.b  D0,-(A5)  ; PHA
    even
_L_z07_GetCollidableTile_AsIsX:
    ; Take the X coordinate as is.
    ;
    moveq   #0,D3
    move.b  ($70,A4,D2.W),D3
    jmp     _L_z07_GetCollidableTile_FetchTile

    even
_L_z07_GetCollidableTile_AdjustX:
    ; Adjust the X coordinate.
    ;
    moveq   #0,D3
    move.b  ($70,A4,D2.W),D3
    ; If direction is left and X coordinate >= $10
    ; or direction is right and X coordinate < $F0,
    move.b  ($000F,A4),D0
    andi.b #$01,D0
    beq  _L_z07_GetCollidableTile_CheckLeftBoundary
    cmpi.b  #$F0,D3
    bcc  _L_z07_GetCollidableTile_FetchTile
    bcs  _L_z07_GetCollidableTile_AddHotspotOffset
    even
_L_z07_GetCollidableTile_CheckLeftBoundary:
    cmpi.b  #$10,D3
    bcs  _L_z07_GetCollidableTile_FetchTile
    even
_L_z07_GetCollidableTile_AddHotspotOffset:
    move.b  D3,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0004,A4),D1
    addx.b  D1,D0   ; ADC $04
    moveq   #0,D3
    move.b  D0,D3
    even
_L_z07_GetCollidableTile_FetchTile:
    move.b  D3,D0
    andi.b #$F8,D0
    ; Divide this multiple by 4 to get the offset of the 2-byte address.
    ;
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    moveq   #0,D3
    move.b  D0,D3
    lea     (PlayAreaColumnAddrs).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0000,A4)
    lea     (PlayAreaColumnAddrs+1).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0001,A4)
    move.b  (A5)+,D0  ; PLA
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$40,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$40
    eori    #$10,CCR  ; restore X = 6502 C
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    moveq   #0,D3
    move.b  D0,D3
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    lea     ($049E,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  ($000F,A4),D0
    andi.b #$0C,D0
    beq  _L_z07_GetCollidableTile_CheckWalkable
    ; The direction in [0F] is vertical. Check the tile in the next column.
    ; It might be a blocking tile. Blocking tiles are arranged after
    ; walkable tiles.
    ;
    move.b  D3,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$16,D1
    addx.b  D1,D0   ; ADC #$16 (X flag = 6502 C)
    moveq   #0,D3
    move.b  D0,D3
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    lea     ($049E,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    bcs  _L_z07_GetCollidableTile_CheckWalkable
    lea     ($049E,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z07_GetCollidableTile_CheckWalkable:
    lea     ($049E,A4),A0
    move.b  (A0,D2.W),D0
    moveq   #0,D3
    move.b  ($0010,A4),D3
    bne  _L_z07_GetCollidableTile_Exit
    ; Look for the tile in a list of walkable tiles. If it's found,
    ; then turn it into $26 to simplify walkability tests.
    lea     ($049E,A4),A0
    move.b  (A0,D2.W),D0
    moveq   #9,D3
    even
_L_z07_GetCollidableTile_MatchWalkableTile:
    subq.b  #1,D3
    bmi  _L_z07_GetCollidableTile_SetTile
    lea     (WalkableTiles).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bne  _L_z07_GetCollidableTile_MatchWalkableTile
    ; The tile was found in the list. Substitute $26 for it.
    ;
    moveq   #38,D0
    even
_L_z07_GetCollidableTile_SetTile:
    lea     ($049E,A4),A0
    move.b  D0,(A0,D2.W)
    cmpi.b  #$00,D2
    bne  _L_z07_GetCollidableTile_ReturnTile
    move.b  ($00EB,A4),D0
    cmpi.b  #$1F,D0
    bne  _L_z07_GetCollidableTile_ReturnTile
    moveq   #12,D0
    move.b  ($000F,A4),D1
    and.b  D1,D0
    beq  _L_z07_GetCollidableTile_ReturnTile
    ; If Link is at X=$80, Y<$56; then set the tile to walkable tile $26.
    ;
    move.b  ($0070,A4),D0
    cmpi.b  #$80,D0
    bne  _L_z07_GetCollidableTile_ReturnTile
    move.b  ($0084,A4),D0
    cmpi.b  #$56,D0
    bcc  _L_z07_GetCollidableTile_ReturnTile
    moveq   #38,D0
    move.b  D0,($049E,A4)
    even
_L_z07_GetCollidableTile_ReturnTile:
    lea     ($049E,A4),A0
    move.b  (A0,D2.W),D0
    even
_L_z07_GetCollidableTile_Exit:
    rts

    even
Obj_Shove:
    ; If this is not the first call to this routine for this instance of shoving (high bit is clear),
    ; then go handle it separately.
    ;
    lea     ($00C0,A4),A0
    move.b  (A0,D2.W),D0
    lsl.b  #1,D0   ; ASL A
    bcc  _L_z07_Obj_Shove_MoveIfNotDone
    ; Clear the high bit, so we don't repeat this initialization.
    ;
    lsr.b  #1,D0   ; LSR A
    lea     ($00C0,A4),A0
    move.b  D0,(A0,D2.W)
    ; If the object faces horizontally, go check which axis shove
    ; direction is on.
    ;
    moveq   #0,D3
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D3
    cmpi.b  #$03,D3
    bcs  _L_z07_Obj_Shove_FacingHorizontally
    ; The object faces vertically.
    ;
    ; If the shove direction is vertical, return. We're OK to shove.
    ;
    andi.b #$03,D0
    beq  _L_z07_Obj_Shove_Exit
    even
_L_z07_Obj_Shove_CheckPerpendicularShove:
    ; Allow a perpendicular shove, if grid offset = 0.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z07_Obj_Shove_Exit
    ; Else change the shove direction.
    ;
    ; If the object is not Link, then reset it.
    ;
    cmpi.b  #$00,D2
    beq.s  __far_z_07_0044
    jmp  ResetShoveInfo
__far_z_07_0044:
    ; Since it's Link, shove in the opposite direction that he's facing.
    ;
    move.b  ($0098,A4),D0
    jsr     GetOppositeDir
    move.b  D0,($00C0,A4)
    even
_L_z07_Obj_Shove_Exit:
    rts

    even
_L_z07_Obj_Shove_FacingHorizontally:
    ; If shove direction is horizontal, return. We're OK to shove.
    ; Else go check the object's grid offset.
    ;
    andi.b #$0C,D0
    bne  _L_z07_Obj_Shove_CheckPerpendicularShove
    rts

    even
_L_z07_Obj_Shove_MoveIfNotDone:
    ; If shove distance hasn't gone down to 0, go move some more.
    ; Else reset shove info.
    ;
    lea     ($00D3,A4),A0
    move.b  (A0,D2.W),D0
    beq.s  __far_z_07_0045
    jmp  ShoveMoveMin
__far_z_07_0045:
; Returns:
; A: 0
;
    even
ResetShoveInfo:
    moveq   #0,D0
; Params:
; A: 0
;
; Returns:
; A: 0
;
    even
SetShoveInfoWith0:
    lea     ($00C0,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($00D3,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
ShoveMoveMin:
    ; Try to move 4 pixels. [03] is the counter.
    ;
    moveq   #4,D0
    move.b  D0,($0003,A4)
    even
_L_z07_ShoveMoveMin_LoopShovePixel:
    ; If the object's grid offset = 0, make sure it's aligned to the grid.
    ; Then, stop shoving if the object hits a tile.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z07_ShoveMoveMin_CheckBoundary
    jsr     EnsureObjectAligned
    lea     ($00C0,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    move.b  D0,($000F,A4)
    jsr     GetCollidingTileMoving
    move.b  ($034A,A4),D1
    cmp.b   D1,D0
    bcs.s  __far_z_07_0046
    jmp  ResetShoveInfo
__far_z_07_0046:
    even
_L_z07_ShoveMoveMin_CheckBoundary:
    ; Regardless of the grid offset, if the object runs into the
    ; bounds of the room, then stop shoving.
    ;
    lea     ($00C0,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    jsr     BoundByRoomWithA
    bne.s  __far_z_07_0047
    jmp  ResetShoveInfo
__far_z_07_0047:
    ; If there is a grumble moblin or person in the room (regardless
    ; of which object is being shoved), then see if it's blocked by
    ; the person. Stop shoving if it is blocked.
    ;
    move.b  ($0350,A4),D0
    cmpi.b  #$36,D0
    beq  _L_z07_ShoveMoveMin_CheckBlocked
    cmpi.b  #$4B,D0
    bcs  _L_z07_ShoveMoveMin_ChooseSpeed
    cmpi.b  #$53,D0
    bcc  _L_z07_ShoveMoveMin_ChooseSpeed
    even
_L_z07_ShoveMoveMin_CheckBlocked:
    jsr     CheckPersonBlocking
    move.b  ($000F,A4),D0
    bne.s  __far_z_07_0048
    jmp  ResetShoveInfo
__far_z_07_0048:
    even
_L_z07_ShoveMoveMin_ChooseSpeed:
    ; If the direction is right or down, store 1 in [02], else -1.
    ; This is the amount to change the relevant coordinate by.
    ;
    moveq   #1,D3
    lea     ($00C0,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$05,D0
    bne  _anon_z07_13
    move.b  #$FF,D3
_anon_z07_13:
    move.b  D3,($0002,A4)
    ; We're OK to change the position. So, decrease the distance
    ; that's left to move.
    ;
    lea     ($00D3,A4),A0
    subq.b  #1,(A0,D2.W)
    ; Change the grid offset by the amount in [02] (1, -1).
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0002,A4),D1
    addx.b  D1,D0   ; ADC $02
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    ; If grid offset is a multiple of $10, or the object is Link and grid offset
    ; is a multiple of 8, then reset grid offset.
    ;
    andi.b #$0F,D0
    beq  _L_z07_ShoveMoveMin_SetGridOffset
    cmpi.b  #$00,D2
    bne  _L_z07_ShoveMoveMin_ApplySpeed
    andi.b #$07,D0
    bne  _L_z07_ShoveMoveMin_ApplySpeed
    even
_L_z07_ShoveMoveMin_SetGridOffset:
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z07_ShoveMoveMin_ApplySpeed:
    ; If the direction is horizontal, add the amount in [02] to X.
    ;
    lea     ($00C0,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$03,D0
    beq  _L_z07_ShoveMoveMin_AddToY
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0002,A4),D1
    addx.b  D1,D0   ; ADC $02
    move.b  D0,($70,A4,D2.W)
    jmp     _L_z07_ShoveMoveMin_NextShovePixel

    even
_L_z07_ShoveMoveMin_AddToY:
    ; Else add the amount to Y coordinate.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0002,A4),D1
    addx.b  D1,D0   ; ADC $02
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z07_ShoveMoveMin_NextShovePixel:
    ; Loop again if [03] is not going down to 0.
    ;
    subq.b  #1,($0003,A4)
    bne  _L_z07_ShoveMoveMin_LoopShovePixel
    rts

    even
FluteRoomSecretsOW:
    dc.b    $42, $06, $29, $2B, $30, $3A, $3C, $58
    dc.b    $60, $6E, $72

    even
WieldFlute:
    ; Play the flute's tune.
    ;
    moveq   #16,D0
    move.b  D0,($0602,A4)
    ; Set the flute timer for $98 frames.
    ;
    move.b  #$98,D0
    move.b  D0,($003C,A4)
    ; In UW, go flag that we used the flute, and return.
    ;
    move.b  ($0010,A4),D0
    bne  _L_z07_WieldFlute_FlagFluteUsed
    ; If not in mode 5, return.
    ;
    move.b  ($0012,A4),D0
    cmpi.b  #$05,D0
    bne  _L_z07_WieldFlute_Exit
    ; Get and save the quest number.
    ;
    moveq   #0,D3
    move.b  ($0016,A4),D3
    lea     ($062D,A4),A0
    move.b  (A0,D3.W),D0
    move.b  D0,-(A5)  ; PHA
    ; Look for the current room in this list of $A that have a flute secret.
    ;
    move.b  ($00EB,A4),D0
    moveq   #10,D3
    even
_L_z07_WieldFlute_FindSecretRoom:
    lea     (FluteRoomSecretsOW).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    beq  _L_z07_WieldFlute_Found
    subq.b  #1,D3
    bpl  _L_z07_WieldFlute_FindSecretRoom
    bmi  _L_z07_WieldFlute_FluteSecretNotFound
    even
_L_z07_WieldFlute_Found:
    ; Found.
    ;
    ; If it was the first room in the list, handle it specially.
    ; This room is the only one in Q1 with a flute secret. It's also
    ; the only one in the list without a flute secret in Q2.
    ;
    ; In Q2, go summon the whirlwind. In Q1, continue to reveal
    ; the secret.
    ;
    cmpi.b  #$00,D3
    bne  _L_z07_WieldFlute_Normal
    move.b  (A5)+,D0  ; PLA
    bne  _L_z07_WieldFlute_SummonWhirlwind
    beq  _L_z07_WieldFlute_RevealSecret
    even
_L_z07_WieldFlute_Normal:
    ; For other rooms in the list:
    ; In Q1, go summon the whirlwind.
    ; In Q2, continue to reveal the secret.
    ;
    move.b  (A5)+,D0  ; PLA
    beq  _L_z07_WieldFlute_SummonWhirlwind
    even
_L_z07_WieldFlute_RevealSecret:
    ; If the cycle of colors is complete or in progress, then return. The secret is already revealed.
    ;
    move.b  ($051A,A4),D0
    bne  _L_z07_WieldFlute_Exit
    ; TODO:
    ; Look for an empty slot from 8 to 0 (?!).
    ;
    ; TODO:
    ; Does it ever get to 0? Would it work? Would an object in that
    ; slot be updated?
    ;
    moveq   #9,D3
    even
_L_z07_WieldFlute_FindEmptySlot:
    subq.b  #1,D3
    bmi  _L_z07_WieldFlute_Exit
    lea     ($0350,A4),A0
    move.b  (A0,D3.W),D0
    bne  _L_z07_WieldFlute_FindEmptySlot
    ; If we find one, set up a flute secret object there.
    ; It will handle the rest.
    ;
    moveq   #94,D0
    lea     ($0350,A4),A0
    move.b  D0,(A0,D3.W)
    even
_L_z07_WieldFlute_Exit:
    rts

    even
_L_z07_WieldFlute_FluteSecretNotFound:
    ; Not found.
    ;
    ;
    ; Pop and throw away the quest number.
    ;
    move.b  (A5)+,D0  ; PLA
    even
_L_z07_WieldFlute_SummonWhirlwind:
    ; Summon the whirlwind.
    ;
    moveq   #1,D0
    jsr     SwitchBank
    jsr     SummonWhirlwind
    moveq   #5,D0
    jmp     SwitchBank

    even
_L_z07_WieldFlute_FlagFluteUsed:
    ; Flag that we used the flute.
    ;
    move.b  ($051B,A4),D0
    beq.s  __far_z_07_0049
    jmp  L1EFCF_Exit
__far_z_07_0049:
    addq.b  #1,($051B,A4)
    even
L1EFCF_Exit:
    rts

    even
Walker_Move:
    ; If the object is being shoved, then go shove it.
    ;
    lea     ($00C0,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z07_Walker_Move_ChooseObjDirOrInputDir
    jmp     Obj_Shove

    even
_L_z07_Walker_Move_ChooseObjDirOrInputDir:
    ; Summary: Choose object direction or input direction for movement as appropriate.
    ;
    ; Player: If there's input, then use input direction when grid offset = 0,
    ;         or object direction when <> 0.
    ;
    ; Other objects: Move in input direction, unless stunned or magic clock is active.
    ;
    ; if slot = 0 and grid offset <> 0 then
    ;   if input dir = 0 then
    ;     use 0
    ;   else
    ;     use object direction
    ; else
    ;   if slot <> 0 and (has clock or stunned) then
    ;     return
    ;   else
    ;     if input dir = 0
    ;       use 0
    ;     else
    ;       use input direction
    ;
    cmpi.b  #$00,D2
    bne  _L_z07_Walker_Move_CheckStunned
    move.b  ($0394,A4),D0
    beq  _L_z07_Walker_Move_CheckStunned
    move.b  ($03F8,A4),D0
    beq  _L_z07_Walker_Move_ZeroMovingDir
    move.b  ($0098,A4),D0
    bne  _L_z07_Walker_Move_SetMovingDir
    even
_L_z07_Walker_Move_CheckStunned:
    cmpi.b  #$00,D2
    beq  _L_z07_Walker_Move_FilterInput
    move.b  ($066C,A4),D0
    move.b  ($3D,A4,D2.W),D1
    or.b  D1,D0
    beq.s  __far_z_07_0050
    jmp  L1EFCF_Exit
__far_z_07_0050:
    even
_L_z07_Walker_Move_FilterInput:
    lea     ($03F8,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z07_Walker_Move_ZeroMovingDir
    jsr     GetOppositeDir
    lea     (ReverseDirections).l,A0
    move.b  (A0,D3.W),D0
    bne  _L_z07_Walker_Move_SetMovingDir
    even
_L_z07_Walker_Move_ZeroMovingDir:
    moveq   #0,D0
    even
_L_z07_Walker_Move_SetMovingDir:
    ; Mask off everything but directions.
    ; (I don't think there's anything else)
    ;
    andi.b #$0F,D0
    move.b  D0,($000F,A4)
    ; [0E]: $FF, if blocked by a door
    ;       else will hold the reverse index of the direction of a doorway if found
    ; 
    moveq   #0,D0
    move.b  D0,($000E,A4)
    ; If object is Link and using or catching an item then
    ; reset movement direction.
    ;
    cmpi.b  #$00,D2
    bne  _L_z07_Walker_Move_OnlyLink
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$F0,D0
    cmpi.b  #$10,D0
    beq  _anon_z07_14
    cmpi.b  #$20,D0
    bne  _L_z07_Walker_Move_OnlyLink
_anon_z07_14:
    move.b  D2,($000F,A4)
    even
_L_z07_Walker_Move_OnlyLink:
    ; If object is not Link, then skip the code below.
    ;
    cmpi.b  #$00,D2
    bne  _L_z07_Walker_Move_CheckBoundary
    ; Check if tile objects block the player.
    ;
    moveq   #1,D0
    jsr     SwitchBank
    jsr     CheckTileObjectsBlocking
    ; Check whether a person blocks the player.
    ;
    move.b  ($0350,A4),D0
    cmpi.b  #$36,D0
    beq  _L_z07_Walker_Move_CheckBlocked
    cmpi.b  #$4B,D0
    bcs  _L_z07_Walker_Move_CheckSubroomOrDoorways
    cmpi.b  #$53,D0
    bcc  _L_z07_Walker_Move_CheckSubroomOrDoorways
    even
_L_z07_Walker_Move_CheckBlocked:
    jsr     CheckPersonBlocking
    even
_L_z07_Walker_Move_CheckSubroomOrDoorways:
    ; If in a doorway, then go check doorways instead of subrooms.
    ;
    move.b  ($0053,A4),D0
    bne  _L_z07_Walker_Move_CheckDoorways
    ; Check subrooms (caves and cellars) in modes 9, $B, $C.
    ;
    move.b  ($0012,A4),D0
    cmpi.b  #$09,D0
    beq  _L_z07_Walker_Move_InSubroom
    cmpi.b  #$0B,D0
    beq  _L_z07_Walker_Move_InSubroom
    cmpi.b  #$0C,D0
    bne  _L_z07_Walker_Move_SkipSubroom
    even
_L_z07_Walker_Move_InSubroom:
    moveq   #5,D0
    jsr     SwitchBank
    jsr     CheckSubroom
    ; If game mode = 9, or in OW, or in a doorway, then skip
    ; checking room boundaries.
    ;
    move.b  ($0012,A4),D0
    cmpi.b  #$09,D0
    beq  _L_z07_Walker_Move_CheckDoorways
    even
_L_z07_Walker_Move_SkipSubroom:
    move.b  ($0010,A4),D0
    beq  _L_z07_Walker_Move_CheckDoorways
    move.b  ($0053,A4),D0
    bne  _L_z07_Walker_Move_CheckDoorways
    even
_L_z07_Walker_Move_CheckBoundary:
    ; This code applies to all objects.
    ;
    ; Prevents movement outside the walls or border of a room,
    ; even Link in front of a doorway.
    ;
    jsr     BoundByRoom
    even
_L_z07_Walker_Move_CheckDoorways:
    ; If object is Link, and level is in UW, and mode <> 9,
    ; then check doorways.
    ;
    cmpi.b  #$00,D2
    bne  _L_z07_Walker_Move_CheckTiles
    move.b  ($0010,A4),D0
    beq  _L_z07_Walker_Move_CheckTiles
    move.b  ($0012,A4),D0
    cmpi.b  #$09,D0
    beq  _L_z07_Walker_Move_CheckTiles
    moveq   #5,D0
    jsr     SwitchBank
    jsr     CheckDoorway
    moveq   #0,D2
    even
_L_z07_Walker_Move_CheckTiles:
    ; This code applies to all objects.
    ;
    jsr     Walker_CheckTileCollision
    ; The player will check for the ladder.
    ;
    cmpi.b  #$00,D2
    beq.s  __far_z_07_0051
    jmp  MoveObject
__far_z_07_0051:
    moveq   #5,D0
    jsr     SwitchBank
    jsr     CheckLadder
; Params:
; X: object index
; [0F]: direction
;
;
; Positive limit is 8 for Link.
    even
MoveObject:
    moveq   #8,D0
    move.b  #$F8,D3
    cmpi.b  #$00,D2
    beq  _anon_z07_15
    moveq   #16,D0
    move.b  #$F0,D3
_anon_z07_15:
    move.b  D0,($010E,A4)
    move.b  D3,($010F,A4)
    move.b  ($000F,A4),D0
    beq  _L_z07_MoveObject_Exit
    ; To allow a wide speed range, we keep the quarter speed.
    ; Here, apply it 4 times to get the full speed.
    bsr     _L_z07_MoveObject_ApplyQSpeedToPosition
    bsr     _L_z07_MoveObject_ApplyQSpeedToPosition
    bsr     _L_z07_MoveObject_ApplyQSpeedToPosition
    even
_L_z07_MoveObject_ApplyQSpeedToPosition:
    move.b  ($000F,A4),D0
    lsr.b  #1,D0   ; LSR A
    bcs  _L_z07_MoveObject_Right
    lsr.b  #1,D0   ; LSR A
    bcs  _L_z07_MoveObject_Left
    lsr.b  #1,D0   ; LSR A
    bcs  _L_z07_MoveObject_Down
    ; Up
    ;
    jsr     SubQSpeedFromPositionFraction
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  #$00,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$00
    eori    #$10,CCR  ; restore X = 6502 C
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z07_MoveObject_Exit:
    rts

    even
_L_z07_MoveObject_Down:
    ; Down
    ;
    jsr     AddQSpeedToPositionFraction
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  #$00,D1
    addx.b  D1,D0   ; ADC #$00 (X flag = 6502 C)
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
_L_z07_MoveObject_Right:
    ; Right
    ;
    jsr     AddQSpeedToPositionFraction
    move.b  ($70,A4,D2.W),D0
    move.b  #$00,D1
    addx.b  D1,D0   ; ADC #$00 (X flag = 6502 C)
    move.b  D0,($70,A4,D2.W)
    rts

    even
_L_z07_MoveObject_Left:
    ; Left
    ;
    jsr     SubQSpeedFromPositionFraction
    move.b  ($70,A4,D2.W),D0
    move.b  #$00,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$00
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($70,A4,D2.W)
    eori    #$01,CCR  ; normalize C to 6502 polarity before RTS
    rts

; Up, down, left, right.
;
    even
PlayerScreenEdgeBounds:
    dc.b    $3D, $DD, $00, $F0

; Params:
; [0E]: $FF, if blocked by a door
; [0F]: movement direction
;
; Returns:
; [0F]: untouched, or changed if blocked or need to change
;
; Summary:
;
; For the player: if at a doorway or walkable tile, check the screen edge.
; Then allow movement or go to the next room. Otherwise,
; check passive tile objects and stop moving.
;
; For other objects: First, if moving, test the colliding tile for
; walkability. Otherwise search for a walkable direction starting
; from input direction.
;
; When you find a walkable direction, see if it makes the object
; cross a boundary. If it doesn't, then make this direction
; the objection direction. Otherwise, keep looping.
;
; If no walkable direction is found, then stop moving.
;
;
; if is player
;   if at doorway
;     go handle a walkable direction
;   if blocked by door
;     return
;
    even
Walker_CheckTileCollision:
    ifne TURBO_LINK
    tst.b   D2
    bne.s   _L_z07_Walker_CheckTileCollision_notLink
    ; Link no-clip: skip tile collision but still call
    ; CheckScreenEdge so screen transitions still latch.
    jsr     CheckScreenEdge    ; PATCH P40: edge-trigger preserved
    rts
_L_z07_Walker_CheckTileCollision_notLink:
    endc
    cmpi.b  #$00,D2
    bne  _L_z07_Walker_CheckTileCollision_CheckGridOffset
    move.b  ($0053,A4),D0
    beq  _anon_z07_16
    jmp     GoWalkableDir

_anon_z07_16:
    move.b  ($000E,A4),D0
    bpl.s  __far_z_07_0052
    jmp  L1F148_Exit
__far_z_07_0052:
    even
_L_z07_Walker_CheckTileCollision_CheckGridOffset:
    ; If grid offset <> 0, return.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    beq.s  __far_z_07_0053
    jmp  L1F148_Exit
__far_z_07_0053:
    ; Grid offset = 0.
    ; The object is at a point between cells in the grid.
    ; So, we can check tiles for collision.
    ;
    ; Reset [0E] alternate direction search step.
    ;
    move.b  D0,($000E,A4)
    ; If there's a movement direction, go check tile collision.
    ;
    move.b  ($000F,A4),D0
    beq.s  __far_z_07_0054
    jmp  CheckTiles
__far_z_07_0054:
    ; Moving direction = 0.
    ; If object is the player, return.
    ;
    cmpi.b  #$00,D2
    bne.s  __far_z_07_0055
    jmp  L1F148_Exit
__far_z_07_0055:
    ; Moving direction = 0.
    ; The object is not the player.
    ;
    ; If object does not have attribute $10, then
    ; set movement direction to input direction,
    ; and go try to turn to an unblocked direction in order to move.
    ;
    lea     ($04BF,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$10,D0
    beq.s  __far_z_07_0056
    jmp  Reverse
__far_z_07_0056:
    lea     ($03F8,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($000F,A4)
    jmp     TryNextDir

    even
Reverse:
    ; UNKNOWN:
    ; This seems to be unused code triggered by object attribute $10.
    ; But $10 is not used in the object attribute array at 07:FAEF.
    ;
    jsr     ReverseObjDir
    jmp     CheckBoundary

    even
CheckTiles:
    ; The code below applies to Link and other objects.
    ;
    ; Test the moving direction's walkability.
    ;
    ; For the player, this is enough. For other objects, this 
    ; becomes a loop looking for an unblocked direction to move in.
    ;
    ; If the colliding tile is walkable, go handle a walkable direction.
    ;
    jsr     GetCollidingTileMoving
    move.b  ($034A,A4),D1
    cmp.b   D1,D0
    bcc.s  __far_z_07_0057
    jmp  GoWalkableDir
__far_z_07_0057:
    ; The colliding tile is unwalkable.
    ;
    ; If object is the player, then go check passive tile objects and
    ; the screen edge, or stop moving.
    ;
    cmpi.b  #$00,D2
    bne.s  __far_z_07_0058
    jmp  PlayerUnwalkable
__far_z_07_0058:
    even
CheckObjAttr10AndAltDir:
    ; Not the player.
    ; If object attribute has $10, go to the unused code above
    ; to reverse direction.
    ;
    lea     ($04BF,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$10,D0
    beq.s  __far_z_07_0059
    jmp  Reverse
__far_z_07_0059:
    even
TryNextDir:
    ; Get the next direction to check, and set moving direction to it.
    ; If not at the end of the loop, go test the new direction's walkability.
    ;
    jsr     Walker_GetNextAltDir
    move.b  D0,($000F,A4)
    move.b  ($000E,A4),D0
    beq.s  __far_z_07_0060
    jmp  CheckTiles
__far_z_07_0060:
    rts

    even
PlayerUnwalkable:
    ; Tile is not walkable. Object is player.
    ;
    ; Check passive tile objects and the screen edge, and stop moving.
    ;
    ; First, if in OW, check passive tile objects (armos and regular gravestone).
    ;
    move.b  ($0010,A4),D0
    bne  _L_z07_PlayerUnwalkable_StopMoving
    moveq   #1,D0
    jsr     SwitchBank
    jsr     CheckPassiveTileObjects
    even
_L_z07_PlayerUnwalkable_StopMoving:
    ; Reset moving direction and buttons pressed.
    ; If in UW, we're done.
    ; In OW, go check the screen edge.
    ;
    jsr     ResetMovingDir
    move.b  D0,($00F8,A4)
    move.b  ($0010,A4),D0
    bne.s  __far_z_07_0061
    jmp  GoWalkableDir
__far_z_07_0061:
    even
L1F148_Exit:
    rts

; Returns:
; A: 0
; [0F]: 0
;
    even
ResetMovingDir:
    moveq   #0,D0
    move.b  D0,($000F,A4)
    rts

    even
GoWalkableDir:
    ; If object is not Link, then the tile is walkable. Go see if this direction
    ; makes the object cross a boundary. Then go check another direction if it does,
    ; or else make this the object direction.
    ;
    cmpi.b  #$00,D2
    beq.s  __far_z_07_0062
    jmp  CheckBoundary
__far_z_07_0062:
    ; The object is Link. We end up here regardless of walkability.
    ;
    ; If not in mode 5 or ladder is in use, return.
    ;
    move.b  ($0012,A4),D0
    cmpi.b  #$05,D0
    beq.s  __far_z_07_0063
    jmp  ExitX0
__far_z_07_0063:
    move.b  ($0064,A4),D0
    beq.s  __far_z_07_0064
    jmp  L1F148_Exit
__far_z_07_0064:
    ; If grid offset <> 0, return.
    ;
    move.b  ($0394,A4),D0
    beq.s  __far_z_07_0065
    jmp  ExitX0
__far_z_07_0065:
    even
CheckScreenEdge:
    moveq   #0,D2
    move.b  ($0084,A4),D2
    ; If not moving, then return.
    ;
    move.b  ($03F8,A4),D0
    bne.s  __far_z_07_0066
    jmp  ExitX0
__far_z_07_0066:
    ; If the single moving direction is vertical, use Y.
    ; Else use X coordinate.
    ;
    ;
    ; Call this to get a single moving direction.
    jsr     GetOppositeDir
    lea     (ReverseDirections).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$0C,D0
    bne  _anon_z07_17
    moveq   #0,D2
    move.b  ($0070,A4),D2
_anon_z07_17:
    move.b  D2,($0000,A4)
    ; If Link's coordinate does not match the screen edge coordinate
    ; in the single moving direction, then return.
    ;
    move.b  ($0000,A4),D0
    lea     (PlayerScreenEdgeBounds).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    beq.s  __far_z_07_0067
    jmp  ExitX0
__far_z_07_0067:
    ; We're moving to the next screen.
    ; Make sure Link faces the single moving direction.
    ;
    lea     (ReverseDirections).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0098,A4)
; Returns:
; X: 0 (Link's object slot)
;
    even
GoToNextModeFromPlay:
    addq.b  #1,($0012,A4)
    moveq   #0,D0
    move.b  D0,($0013,A4)
    move.b  D0,($0011,A4)
    move.b  D0,($000F,A4)
    move.b  D0,($00AC,A4)
    move.b  D0,($00C0,A4)
    move.b  D0,($00D3,A4)
    move.b  D0,($04F0,A4)
    even
ExitX0:
    moveq   #0,D2
    rts

    even
CheckBoundary:
    ; If object crossed a boundary, then go check object
    ; attribute $10 and another direction.
    ; Else set object direction to moving direction [0F] and return.
    ;
    jsr     BoundByRoom
    bne.s  __far_z_07_0068
    jmp  CheckObjAttr10AndAltDir
__far_z_07_0068:
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    rts

; Description:
; Calculates the next alternate direction to move in while
; searching for an unblocked direction.
;
; Params:
; [0E]: the current step
;
; Returns:
; A: a direction for the current step, or 0 at the end of the loop
; [0E]: the next step, or 0 to end the loop
; ObjDir: might be modified
;
    even
Walker_GetNextAltDir:
    move.b  ($000E,A4),D0
    addq.b  #1,($000E,A4)
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
Walker_GetNextAltDir_JumpTable:
    dc.l    Walker_AltDir_GetRandomObjPerpendicularDir   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Walker_AltDir_GetMovingOppositeDir   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    ReverseObjDir   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    Walker_AltDir_EndLoop   ; jump table entry (32-bit for _m68k_tablejump)

    even
Walker_AltDir_GetRandomObjPerpendicularDir:
    moveq   #0,D3
    move.b  ($18,A4,D2.W),D0
    lsl.b  #1,D0   ; ASL A
    bcs  _anon_z07_18
    addq.b  #1,D3
_anon_z07_18:
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0C,D0
    beq  _anon_z07_19
    addq.b  #1,D3
    addq.b  #1,D3
_anon_z07_19:
    lea     (ReverseDirections).l,A0
    move.b  (A0,D3.W),D0
    rts

    even
Walker_AltDir_GetMovingOppositeDir:
    move.b  ($000F,A4),D0
    move.b  D0,-(A5)  ; PHA
    andi.b #$0A,D0
    beq  _L_z07_Walker_AltDir_GetMovingOppositeDir_IncreasingDir
    move.b  (A5)+,D0  ; PLA
    lsr.b  #1,D0   ; LSR A
    rts

    even
_L_z07_Walker_AltDir_GetMovingOppositeDir_IncreasingDir:
    move.b  (A5)+,D0  ; PLA
    lsl.b  #1,D0   ; ASL A
    rts

    even
ReverseObjDir:
    ; Note:
    ; Also reverses movement direction in [0F].
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    jsr     GetOppositeDir
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D0,($000F,A4)
    rts

    even
Walker_AltDir_EndLoop:
    moveq   #0,D0
    move.b  D0,($000E,A4)
    rts

; Description:
; Search for an unblocked direction. Set facing direction to it,
; if one is found.
;
; If not at a square boundary, then return.
;
    even
_FaceUnblockedDir:
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    beq.s  __far_z_07_0069
    jmp  L1F1FC_Exit
__far_z_07_0069:
    ; Else reset [0E] to start the search for an unblocked direction.
    ;
    move.b  D0,($000E,A4)
    even
_L_z07__FaceUnblockedDir_LoopSearchStep:
    jsr     Walker_GetNextAltDir
    ; Set the moving direction [0F] to the direction returned.
    ;
    move.b  D0,($000F,A4)
    ; But quit if none was found.
    ;
    bne.s  __far_z_07_0070
    jmp  L1F1FC_Exit
__far_z_07_0070:
    ; If blocked in this direction by a tile or the room boundary,
    ; then loop again.
    ;
    jsr     GetCollidingTileMoving
    move.b  ($034A,A4),D1
    cmp.b   D1,D0
    bcc  _L_z07__FaceUnblockedDir_LoopSearchStep
    jsr     BoundByRoom
    beq  _L_z07__FaceUnblockedDir_LoopSearchStep
    ; Set the facing direction to the one found.
    ;
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    even
L1F1FC_Exit:
    rts

    even
LinkToLadderOffsetsX:
    dc.b    $00, $00, $F0, $10

    even
LinkToLadderOffsetsY:
    dc.b    $FB, $13, $03, $03

    even
LinkHeadTiles:
    dc.b    $02, $06, $08, $0A

    even
LinkHeadMagicShieldTiles:
    dc.b    $80, $54, $60, $60

    even
LadderRoomsOW:
    dc.b    $17, $18, $19, $27, $4F, $5F

    even
Link_EndMoveAndAnimate_Bank4:
    jsr     Link_EndMoveAndAnimate
    moveq   #4,D0
    jmp     SwitchBank

    even
Link_EndMoveAndDraw_Bank1:
    jsr     Link_EndMoveAndDraw
_anon_z07_20:
    moveq   #1,D0
    jmp     SwitchBank

    even
Link_EndMoveAndAnimate_Bank1:
    jsr     Link_EndMoveAndAnimate
    jmp     _anon_z07_20

    even
Link_EndMoveAndDraw_Bank4:
    jsr     Link_EndMoveAndDraw
    moveq   #4,D0
    jmp     SwitchBank

; Description:
; Draw Link without animating by keeping the animation counter fixed.
;
    even
Link_EndMoveAndDraw:
    moveq   #6,D0
    move.b  D0,($03D0,A4)
    beq.s  __far_z_07_0071
    jmp  Link_EndMoveAndAnimate
__far_z_07_0071:
    even
Link_EndMoveAndAnimateBetweenRooms:
    move.b  ($0010,A4),D0
    beq.s  __far_z_07_0072
    jmp  L1F1FC_Exit
__far_z_07_0072:
    even
Link_EndMoveAndAnimate:
    ; Switches bank: 5
    ;
    ; If teleporting by whirlwind, then return.
    ;
    move.b  ($0522,A4),D0
    beq.s  __far_z_07_0073
    jmp  L1F1FC_Exit
__far_z_07_0073:
    ; If mode 4 or 6 (not a playing mode), then go check warps and animate.
    ;
    moveq   #0,D2
    move.b  D0,D2
    move.b  ($0012,A4),D0
    cmpi.b  #$06,D0
    beq  _L_z07_Link_EndMoveAndAnimate_CheckWarpsAndAnimate
    cmpi.b  #$05,D0
    bcs  _L_z07_Link_EndMoveAndAnimate_CheckWarpsAndAnimate
    ; If Link's grid offset = 0, go see whether we need to wield the ladder.
    ; If Link's grid offset is not a multiple of 8, go check warps and animate.
    ;
    move.b  ($0394,A4),D0
    beq  _L_z07_Link_EndMoveAndAnimate_CheckLadderRoom
    andi.b #$07,D0
    beq  _L_z07_Link_EndMoveAndAnimate_TruncGridOffset
    even
_L_z07_Link_EndMoveAndAnimate_CheckWarpsAndAnimate:
    jmp     _L_z07_Link_EndMoveAndAnimate_CheckWarps

    even
_L_z07_Link_EndMoveAndAnimate_TruncGridOffset:
    ; Grid offset is a multiple of 8. So set it to 0.
    ; If not in mode 5, go check warps and animate.
    ;
    moveq   #0,D0
    move.b  D0,($0394,A4)
    moveq   #0,D3
    move.b  ($0012,A4),D3
    cmpi.b  #$05,D3
    bne  _L_z07_Link_EndMoveAndAnimate_CheckWarpsAndAnimate
    ; Grid offset was a multiple of 8. So, we've stepped a whole tile,
    ; and need to reset the subroom indicator.
    ;
    ; That way, we know not to go into a subroom that we just came out of.
    ;
    move.b  D0,($005A,A4)
    even
_L_z07_Link_EndMoveAndAnimate_CheckLadderRoom:
    ; If not in mode 5, go check warps and animate.
    ;
    move.b  ($0012,A4),D0
    cmpi.b  #$05,D0
    bne  _L_z07_Link_EndMoveAndAnimate_CheckWarpsAndAnimate
    ; If in OW and we're not in this list of 6 rooms, go check warps and animate.
    ;
    move.b  ($0010,A4),D0
    bne  _L_z07_Link_EndMoveAndAnimate_CheckLadder
    move.b  ($00EB,A4),D0
    moveq   #5,D3
    even
_L_z07_Link_EndMoveAndAnimate_LoopLadderRoom:
    lea     (LadderRoomsOW).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    beq  _L_z07_Link_EndMoveAndAnimate_CheckLadder
    subq.b  #1,D3
    bpl  _L_z07_Link_EndMoveAndAnimate_LoopLadderRoom
    bmi  _L_z07_Link_EndMoveAndAnimate_CheckWarps
    even
_L_z07_Link_EndMoveAndAnimate_CheckLadder:
    ; If in a doorway or missing the ladder, go check warps and animate.
    ;
    move.b  ($0053,A4),D0
    bne  _L_z07_Link_EndMoveAndAnimate_CheckWarps
    move.b  ($0663,A4),D0
    beq  _L_z07_Link_EndMoveAndAnimate_CheckWarps
    ; If Link is halted or using the ladder, go check warps and animate.
    ;
    move.b  ($00AC,A4),D0
    andi.b #$C0,D0
    cmpi.b  #$40,D0
    beq  _L_z07_Link_EndMoveAndAnimate_CheckWarps
    move.b  ($0064,A4),D0
    bne  _L_z07_Link_EndMoveAndAnimate_CheckWarps
    ; Get the colliding tile in moving direction.
    ;
    moveq   #0,D2
    move.b  ($0098,A4),D0
    move.b  D0,($000F,A4)
    jsr     GetCollidingTileMoving
    ; If in OW and tile is not water (as in < $8D or >= $99), then
    ; go check warps and animate.
    ; If in UW, and tile <> $F4, go check warps and animate.
    ;
    moveq   #0,D3
    move.b  ($0010,A4),D3
    beq  _L_z07_Link_EndMoveAndAnimate_CheckWaterOW
    cmpi.b  #$F4,D0
    beq  _L_z07_Link_EndMoveAndAnimate_SetUpLadder
    bne  _L_z07_Link_EndMoveAndAnimate_CheckWarps
    even
_L_z07_Link_EndMoveAndAnimate_CheckWaterOW:
    cmpi.b  #$8D,D0
    bcs  _L_z07_Link_EndMoveAndAnimate_CheckWarps
    cmpi.b  #$99,D0
    bcc  _L_z07_Link_EndMoveAndAnimate_CheckWarps
    even
_L_z07_Link_EndMoveAndAnimate_SetUpLadder:
    ; Look for an empty monster slot.
    ; If none found, or input dir = 0, or input direction <> facing direction,
    ; then go check warps and animate.
    ;
    jsr     FindEmptyMonsterSlot
    beq  _L_z07_Link_EndMoveAndAnimate_CheckWarps
    move.b  ($03F8,A4),D0
    beq  _L_z07_Link_EndMoveAndAnimate_CheckWarps
    moveq   #0,D2
    move.b  ($0059,A4),D2
    move.b  ($0098,A4),D1
    cmp.b   D1,D0
    bne  _L_z07_Link_EndMoveAndAnimate_CheckWarps
    ; X register now holds the ladder's slot.
    ; Set ladder slot to empty slot found.
    ; Set ladder's direction to input direction.
    ;
    move.b  D2,($0064,A4)
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; Add appropriate offset to player's position to set the ladder's position.
    ;
    ;
    ; Call this for the reverse direction index.
    jsr     GetOppositeDir
    move.b  ($0070,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (LinkToLadderOffsetsX).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC LinkToLadderOffsetsX,Y
    move.b  D0,($70,A4,D2.W)
    move.b  ($0084,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (LinkToLadderOffsetsY).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC LinkToLadderOffsetsY,Y
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set the ladder object's type. Reset shove params and invincibility timer.
    ;
    ;
    ; Ladder
    moveq   #95,D0
    lea     ($034F,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     ResetShoveInfo
    lea     ($04F0,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set the initial state of the ladder.
    ;
    moveq   #1,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z07_Link_EndMoveAndAnimate_CheckWarps:
    ; If in mode 5, check warps.
    ;
    ;
    ; Set X to 0 to refer to Link object.
    moveq   #0,D2
    move.b  ($0012,A4),D0
    cmpi.b  #$05,D0
    bne  _L_z07_Link_EndMoveAndAnimate_Animate
    move.b  ($049E,A4),D0
    move.b  D0,-(A5)  ; PHA
    moveq   #5,D0
    jsr     SwitchBank
    jsr     CheckWarps
    moveq   #0,D2
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($049E,A4)
    even
_L_z07_Link_EndMoveAndAnimate_Animate:
    ; Animate Link.
    ;
    jsr     AnimateLinkBase
    move.b  ($0012,A4),D0
    cmpi.b  #$09,D0
    beq  _L_z07_Link_EndMoveAndAnimate_ShiftDown2Pixels
    move.b  ($0010,A4),D0
    bne  _L_z07_Link_EndMoveAndAnimate_ChangeLookForState
    even
_L_z07_Link_EndMoveAndAnimate_ShiftDown2Pixels:
    addq.b  #1,($0001,A4)
    addq.b  #1,($0001,A4)
    even
_L_z07_Link_EndMoveAndAnimate_ChangeLookForState:
    ; Now change Link's look for specific states and items.
    ;
    ; If Link is attacking or using an item,
    ; then add 4 to frame to use the "attack/use item" frames.
    move.b  ($00AC,A4),D0
    andi.b #$30,D0
    cmpi.b  #$10,D0
    beq  _L_z07_Link_EndMoveAndAnimate_WieldingObject
    cmpi.b  #$20,D0
    bne  _L_z07_Link_EndMoveAndAnimate_Draw
    even
_L_z07_Link_EndMoveAndAnimate_WieldingObject:
    move.b  D3,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$04,D1
    addx.b  D1,D0   ; ADC #$04 (X flag = 6502 C)
    moveq   #0,D3
    move.b  D0,D3
    even
_L_z07_Link_EndMoveAndAnimate_Draw:
    move.b  D3,D0
    moveq   #0,D3
    jsr     DrawObjectWithAnim
    ; See if there's special processing needed for the shield.
    ;
    move.b  ($0676,A4),D0
    bne  _L_z07_Link_EndMoveAndAnimate_HandleMagicShield
    ; No magic shield.
    ;
    move.b  ($0098,A4),D0
    cmpi.b  #$04,D0
    beq.s  __far_z_07_0074
    jmp  L1F36A_Exit
__far_z_07_0074:
    moveq   #1,D2
    lea     ($0248,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$0B,D0
    bcs.s  __far_z_07_0075
    jmp  L1F36A_Exit
__far_z_07_0075:
    move.b  D0,-(A5)  ; PHA
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$50,D1
    addx.b  D1,D0   ; ADC #$50 (X flag = 6502 C)
    jmp     _L_z07_Link_EndMoveAndAnimate_ApplyShieldSprite

    even
_L_z07_Link_EndMoveAndAnimate_HandleMagicShield:
    ; Magic shield.
    ;
    ;
    ; Look at the left tile.
    moveq   #1,D2
    move.b  ($0098,A4),D0
    lsr.b  #1,D0   ; LSR A
    bcc  _anon_z07_21
    moveq   #5,D2
_anon_z07_21:
    moveq   #4,D3
    lea     ($0248,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    even
_L_z07_Link_EndMoveAndAnimate_LoopHeadTile:
    ; Compare the sprite's tile with 4 tiles: 1 for each direction.
    ;
    subq.b  #1,D3
    bmi  _L_z07_Link_EndMoveAndAnimate_FixHFlip
    lea     (LinkHeadTiles).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bne  _L_z07_Link_EndMoveAndAnimate_LoopHeadTile
    lea     (LinkHeadMagicShieldTiles).l,A0
    move.b  (A0,D3.W),D0
    even
_L_z07_Link_EndMoveAndAnimate_ApplyShieldSprite:
    ; Apply the sprite's modification for the shield.
    ;
    lea     ($0248,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z07_Link_EndMoveAndAnimate_FixHFlip:
    move.b  (A5)+,D0  ; PLA
    cmpi.b  #$0A,D0
    beq.s  __far_z_07_0076
    jmp  L1F36A_Exit
__far_z_07_0076:
    ; It's a down facing tile. Make sure it's not flipped,
    ; because there's only 1 frame of downward shield tile.
    lea     ($0249,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    lea     ($0249,A4),A0
    move.b  D0,(A0,D2.W)
    even
L1F36A_Exit:
    rts

; Sprite attributes that flip each corner of the spread shot
; differently: H, H-V, V, 0
;
    even
SwordShotSpreadBaseAttr:
    dc.b    $40, $C0, $80, $00

    even
UpdateSwordShotOrMagicShot:
    ; If the shot is not active, return.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    bne.s  __far_z_07_0077
    jmp  L1F36A_Exit
__far_z_07_0077:
    ; If low bit is set, go handle shot spreading out.
    ;
    lsr.b  #1,D0   ; LSR A
    bcc  _anon_z07_22
    jmp     SpreadShot

_anon_z07_22:
    ; Move the shot.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    bne  _anon_z07_23
_anon_z07_23:
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    jsr     MoveShot
    ; If movement was blocked, go handle the situation.
    ;
    move.b  ($000F,A4),D0
    bne.s  __far_z_07_0078
    jmp  HandleShotBlocked
__far_z_07_0078:
    ; If grid offset is a multiple of 8, reset it.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$07,D0
    beq.s  __far_z_07_0079
    jmp  DrawSwordShotOrMagicShot
__far_z_07_0079:
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    even
DrawSwordShotOrMagicShot:
    ; Prepare the sprite position.
    ;
    jsr     Anim_FetchObjPosForSpriteDescriptor
    ; If the direction is horizontal, move the sprites down 3 pixels.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    andi.b #$03,D0
    beq  _L_z07_DrawSwordShotOrMagicShot_Flash
    move.b  ($0001,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$03,D1
    addx.b  D1,D0   ; ADC #$03 (X flag = 6502 C)
    move.b  D0,($0001,A4)
    even
_L_z07_DrawSwordShotOrMagicShot_Flash:
    move.b  (A5)+,D0  ; PLA
    ; Set the sprite attributes to (base attribute OR (frame counter AND 3)).
    ; This makes the shot flash by cycling all the palettes, one each frame.
    ;
    ;
    ; Call this only to get reverse direction index.
    jsr     GetOppositeDir
    move.b  ($0015,A4),D0
    andi.b #$03,D0
    lea     (RDirectionToWeaponBaseAttribute).l,A0
    move.b  (A0,D3.W),D1
    or.b  D1,D0
    jsr     Anim_SetSpriteDescriptorAttributes
    ; Set [0C] to the correct frame for the direction: horizontal or vertical.
    ;
    lea     (RDirectionToWeaponFrame).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($000C,A4)
    ; If the direction is left, flip the right facing image by setting [0F] to 1.
    ;
    cmpi.b  #$02,D3
    bne  _anon_z07_24
    addq.b  #1,($000F,A4)
_anon_z07_24:
    ; If this a monster's shot, choose the item slot for drawing based on object type.
    ;   $57 (sword shot) => $22
    ;   other (presumably $58 or $59, magic shot) => $23
    ;
    moveq   #34,D3
    cmpi.b  #$0D,D2
    bcc  _L_z07_DrawSwordShotOrMagicShot_PlayerShot
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$57,D0
    beq  _L_z07_DrawSwordShotOrMagicShot_WriteSprites
    bne  _L_z07_DrawSwordShotOrMagicShot_WriteMagicSprites
    even
_L_z07_DrawSwordShotOrMagicShot_PlayerShot:
    ; But if the player shot it, the choice depends on the shot's state.
    ;   high bit set (magic)   => $23
    ;   high bit clear (sword) => $22
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    lsl.b  #1,D0   ; ASL A
    bcc  _L_z07_DrawSwordShotOrMagicShot_WriteSprites
    even
_L_z07_DrawSwordShotOrMagicShot_WriteMagicSprites:
    moveq   #35,D3
    even
_L_z07_DrawSwordShotOrMagicShot_WriteSprites:
    jmp     Anim_WriteItemSprites

; Params:
; X: shot object index
;
; If the object is a sword shot, go spread out the shot.
;
    even
HandleShotBlocked:
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    lsl.b  #1,D0   ; ASL A
    bcs.s  __far_z_07_0080
    jmp  SetShotSpreadingState
__far_z_07_0080:
    ; This is a magic shot.
    ;
    ; If missing the magic book, go deactivate the shot object.
    ;
    move.b  ($0661,A4),D0
    bne.s  __far_z_07_0081
    jmp  DeactivateShot
__far_z_07_0081:
    ; Try to activate a fire object. Temporarily mark the candle
    ; unused, so it only has to depend on having an empty slot.
    ;
    ; If successful, Link's state will have been changed to "using item".
    ; But we don't want that in this case.
    ;
    ; For both these reasons, save state and restore it afterward.
    ;
    move.b  ($00AC,A4),D0
    move.b  D0,-(A5)  ; PHA
    move.b  ($0513,A4),D0
    move.b  D0,-(A5)  ; PHA
    moveq   #0,D0
    move.b  D0,($0513,A4)
    jsr     WieldCandle
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($0513,A4)
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($00AC,A4)
    ; State $21 means that a moving fire was just made.
    ;
    ; If it's any another value, then we didn't find an empty slot
    ; to make a fire. In this case, all that's left to do is to go
    ; deactivate the shot object.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$21,D0
    beq.s  __far_z_07_0082
    jmp  DeactivateLinkShot
__far_z_07_0082:
    ; Make state $22 for a standing fire.
    ;
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    ; Copy the shot's position and direction to the fire.
    ;
    moveq   #14,D3
    move.b  ($70,A4,D3.W),D0
    move.b  D0,($70,A4,D2.W)
    lea     ($0084,A4),A0
    move.b  (A0,D3.W),D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0098,A4),A0
    move.b  (A0,D3.W),D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; The fire lasts $4F frames.
    ; Deactivate the shot.
    ;
    moveq   #79,D0
    move.b  D0,($28,A4,D2.W)
    even
DeactivateLinkShot:
    moveq   #14,D2
    even
DeactivateShot:
    jmp     ResetObjState

    even
SetShotSpreadingState:
    ; MULTI: ObjDir -> ObjSwordShotNegativeOffset
    ;
    ; Set the state to spreading out (low bit is set).
    ;
    ; Set [98][X] to base negative offset -2. This is how far the left
    ; corners will be shown relative to the center point at object X, Y.
    ; The right corners will be shown 2 pixels in the opposite direction
    ; of the center point.
    ;
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    move.b  #$FE,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
SpreadShot:
    ; MULTI: ObjDir -> ObjSwordShotNegativeOffset
    ;
    ; The shot is spreading out.
    ;
    ; Copy base negative offset in [98][X] to [02] and [03].
    ; These will be negated appropriately for each corner.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0002,A4)
    move.b  D0,($0003,A4)
    ; Reset [0F] to not flip horizontally.
    ;
    moveq   #0,D0
    move.b  D0,($000F,A4)
    ; Loop 4 times to draw each corner of the spreading sword shot.
    ; The corners are: top-left, bottom-left, bottom-right, top-right
    ;
    moveq   #3,D3
    even
_L_z07_SpreadShot_DrawShotCorner:
    move.b  D3,D0
    move.b  D0,-(A5)  ; PHA
    ; Save offset X [02] and Y offset [03].
    ;
    move.b  ($0002,A4),D0
    move.b  D0,-(A5)  ; PHA
    move.b  ($0003,A4),D0
    move.b  D0,-(A5)  ; PHA
    ; Calculate and set sprite attributes for this corner:
    ;   base attribute OR (frame counter AND 3)
    ;
    ; The base attribute defines how to flip the sprite.
    ; The frame counter makes the shot flash by cycling each
    ; palette row.
    ;
    move.b  ($0015,A4),D0
    andi.b #$03,D0
    lea     (SwordShotSpreadBaseAttr).l,A0
    move.b  (A0,D3.W),D1
    or.b  D1,D0
    jsr     Anim_SetSpriteDescriptorAttributes
    ; Add the object's X (the center of the spread) and the
    ; current offset in [02] to set sprite X in [00].
    ;
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0002,A4),D1
    addx.b  D1,D0   ; ADC $02
    move.b  D0,($0000,A4)
    ; If sprite X >= object X and sprite X >= $FC, skip this corner.
    ; Else calculate the distance from object X to sprite X.
    ;
    move.b  ($70,A4,D2.W),D1
    cmp.b   D1,D0
    bcs  _L_z07_SpreadShot_ReverseSub
    cmpi.b  #$FC,D0
    bcc  _L_z07_SpreadShot_NextCorner
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($70,A4,D2.W),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC ObjX,X
    eori    #$10,CCR  ; restore X = 6502 C
    jmp     _L_z07_SpreadShot_CheckDistance

    even
_L_z07_SpreadShot_ReverseSub:
    move.b  ($70,A4,D2.W),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($0000,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $00
    eori    #$10,CCR  ; restore X = 6502 C
    even
_L_z07_SpreadShot_CheckDistance:
    ; If distance >= $20, skip this corner.
    ;
    cmpi.b  #$20,D0
    bcc  _L_z07_SpreadShot_NextCorner
    ; Add the object's Y (the center of the spread) and the
    ; current offset in [03] to set sprite Y in [01].
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0003,A4),D1
    addx.b  D1,D0   ; ADC $03
    move.b  D0,($0001,A4)
    ; If in UW, and (sprite Y < $3E or >= $E8), then skip this corner.
    ;
    moveq   #0,D3
    move.b  ($0010,A4),D3
    beq  _L_z07_SpreadShot_Draw
    cmpi.b  #$3E,D0
    bcs  _L_z07_SpreadShot_NextCorner
    cmpi.b  #$E8,D0
    bcc  _L_z07_SpreadShot_NextCorner
    even
_L_z07_SpreadShot_Draw:
    ; Draw the corner.
    ; Pass [0C] = frame 2 (spread shot), Y = $23 (sword 2).
    ;
    moveq   #2,D0
    move.b  D0,($000C,A4)
    moveq   #35,D3
    jsr     Anim_WriteItemSprites
    even
_L_z07_SpreadShot_NextCorner:
    ; Prepare to process the next corner.
    ;
    ; First, restore X offset [02] and Y offset [03].
    ;
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($0003,A4)
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($0002,A4)
    ; Take turns negating X offset or Y offset for the next round.
    ; - First turn:  loop index = 3, negate Y offset [03]
    ; - Second turn: loop index = 2, negate X offset [02]
    ; - Third turn:  loop index = 1, negate Y offset [03]
    ; - Fourth turn: doesn't matter
    ;
    ;
    ; Get the loop index.
    move.b  (A5)+,D0  ; PLA
    move.b  D0,-(A5)  ; PHA
    moveq   #0,D3
    move.b  D0,D3
    cmpi.b  #$01,D3
    bne  _anon_z07_25
    moveq   #3,D3
_anon_z07_25:
    move.b  ($00,A4,D3.W),D0
    eori.b #$FF,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    move.b  D0,($00,A4,D3.W)
    ; Restore the loop index, decrement it, and loop again if >= 0.
    ;
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D3
    move.b  D0,D3
    subq.b  #1,D3
    bpl  _L_z07_SpreadShot_DrawShotCorner
    ; MULTI: ObjDir -> ObjSwordShotNegativeOffset
    ;
    ; Decrease the base negative offset to get farther away from
    ; the center point.
    ;
    lea     ($0098,A4),A0
    subq.b  #1,(A0,D2.W)
    ; MULTI: ObjDir -> ObjSwordShotNegativeOffset
    ;
    ; Once the base negative offset reaches $E8, go deactivate the object.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$E8,D0
    beq.s  __far_z_07_0083
    jmp  L1F49F_Exit
__far_z_07_0083:
    jmp     DeactivateLinkShot

    even
L1F49F_Exit:
    rts

    even
UpdateBoomerangOrFood:
    ; If state = 0, then not active. So, return.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    bne.s  __far_z_07_0084
    jmp  L1F49F_Exit
__far_z_07_0084:
    ; If the high bit of state is clear, then go update the boomerang.
    ;
    lsl.b  #1,D0   ; ASL A
    bcs.s  __far_z_07_0085
    jmp  UpdateArrowOrBoomerang
__far_z_07_0085:
    ; The object is food.
    ;
    ; Once the timer has expired, increment the state and set timer to $FF.
    ; If we reach state $83, then go deactivate the object.
    ;
    ; Nothing changes between the states. So, they are used as
    ; a way to extend the timer. $2FD screen frames in total.
    ;
    move.b  ($28,A4,D2.W),D0
    bne  _L_z07_UpdateBoomerangOrFood_CheckMonsterType
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    cmpi.b  #$03,D0
    beq  _L_z07_UpdateBoomerangOrFood_Deactivate
    move.b  #$FF,D0
    move.b  D0,($28,A4,D2.W)
    even
_L_z07_UpdateBoomerangOrFood_CheckMonsterType:
    ; If the template object type in the room is one of:
    ; moblin, goriya, octorock, vire, keese
    ; then attract these monsters to the food.
    ;
    ; They will chase the food instead of Link when given a chance.
    ;
    move.b  ($035F,A4),D0
    cmpi.b  #$03,D0
    bcs  _L_z07_UpdateBoomerangOrFood_Draw
    cmpi.b  #$0B,D0
    bcs  _L_z07_UpdateBoomerangOrFood_AttractMonsters
    cmpi.b  #$12,D0
    beq  _L_z07_UpdateBoomerangOrFood_AttractMonsters
    cmpi.b  #$1B,D0
    beq  _L_z07_UpdateBoomerangOrFood_AttractMonsters
    cmpi.b  #$1C,D0
    bne  _L_z07_UpdateBoomerangOrFood_Draw
    even
_L_z07_UpdateBoomerangOrFood_AttractMonsters:
    move.b  ($70,A4,D2.W),D0
    move.b  D0,($0061,A4)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0062,A4)
    even
_L_z07_UpdateBoomerangOrFood_Draw:
    ; Draw the food.
    ;
    jsr     Anim_FetchObjPosForSpriteDescriptor
    moveq   #2,D0
    moveq   #6,D3
    jmp     Anim_WriteStaticItemSpritesWithAttributes

    even
_L_z07_UpdateBoomerangOrFood_Deactivate:
    jmp     ResetObjState

    even
BoomerangFrameCycle:
    dc.b    $00, $01, $02, $01, $00, $01, $02, $01
    dc.b    $03

    even
BoomerangBaseSpriteAttrCycle:
    dc.b    $00, $00, $00, $40, $40, $C0, $80, $80
    dc.b    $01

    even
BoomerangQSpeedFracsY:
    dc.b    $00, $20, $36, $4C, $60, $68, $70, $78
    dc.b    $80

    even
BoomerangQSpeedFracsX:
    dc.b    $80, $78, $70, $68, $60, $4C, $36, $20
    dc.b    $00

    even
RDirectionToWeaponFrame:
    dc.b    $00, $00, $01, $01

; The base sprite attribute for weapon sprites, 1 for each
; direction in reverse direction order: up, down, left, right
;
; All of them are 0, except for the element for "down".
; That one flips the vertical sword or rod image so that it points down.
;
    even
RDirectionToWeaponBaseAttribute:
    dc.b    $00, $80, $00, $00

    even
RDirectionToOffsetsX:
    dc.b    $FC, $FC, $00, $00

    even
RDirectionToOffsetsY:
    dc.b    $00, $00, $03, $03

    even
UpdateArrowOrBoomerang:
    ; If not active (state = 0), then return.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    bne.s  __far_z_07_0086
    jmp  L1F49F_Exit
__far_z_07_0086:
    ; Reset [00], which will hold the number of axes where the distance <= 8
    ; when calculating the angle to return to thrower.
    ; See states $40 and $50 and GetDirectionsAndDistancesToTarget.
    ;
    moveq   #0,D0
    move.b  D0,($0000,A4)
    ; If not in major state $10, go check other states.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$F0,D0
    cmpi.b  #$10,D0
    beq  _L_z07_UpdateArrowOrBoomerang_State10
    jmp     CheckState20

    even
_L_z07_UpdateArrowOrBoomerang_State10:
    ; State $1x. Fly away from the thrower.
    ;
    ; Reset [0E], which will indicate:
    ; - into MoveShot:   0 update grid offset, else don't
    ; - out of MoveShot: $80 if blocked
    ;
    moveq   #0,D0
    move.b  D0,($000E,A4)
    ; If the object's direction has a horizontal component, then
    ; move it horizontally.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$03,D0
    beq  _anon_z07_26
    jsr     MoveShot
    addq.b  #1,($000E,A4)
_anon_z07_26:
    ; If the object was blocked, go handle it.
    ;
    move.b  ($000E,A4),D0
    lsl.b  #1,D0   ; ASL A
    bcs  _L_z07_UpdateArrowOrBoomerang_HandleBlocked
    ; If the object's direction has a vertical component, then
    ; move it vertically.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0C,D0
    beq  _anon_z07_27
    jsr     MoveShot
_anon_z07_27:
    ; If the object was blocked, go handle it.
    ;
    move.b  ($000E,A4),D0
    lsl.b  #1,D0   ; ASL A
    bcs  _L_z07_UpdateArrowOrBoomerang_HandleBlocked
    ; If the object is an arrow (Link's or a monster's), go set up sprite parameters.
    ;
    cmpi.b  #$0D,D2
    bcc  _L_z07_UpdateArrowOrBoomerang_CheckPlayerArrow
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$5B,D0
    bne.s  __far_z_07_0087
    jmp  DrawArrow
__far_z_07_0087:
    even
_L_z07_UpdateArrowOrBoomerang_CheckPlayerArrow:
    cmpi.b  #$12,D2
    bne.s  __far_z_07_0088
    jmp  DrawArrow
__far_z_07_0088:
    ; For boomerangs, get the absolute value of the weapon's grid offset:
    ; the distance traveled.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    bpl  _L_z07_UpdateArrowOrBoomerang_CompareLimit
    eori.b #$FF,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    even
_L_z07_UpdateArrowOrBoomerang_CompareLimit:
    ; For boomerangs, compare it to the movement limit.
    ; If it reached the limit, set state $20 and a new movement
    ; limit of $10, and go handle the rest as if blocked.
    ; State $20 will become $30 below in HandleArrowOrBoomerangBlocked.
    ;
    ; Otherwise, only animate and check collision as usual.
    ;
    ; In major state $30, ObjMovingLimit is a timer to change the state to $40.
    ;
    lea     ($0380,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    bcs  _L_z07_UpdateArrowOrBoomerang_AnimateBoomerang
    moveq   #16,D0
    lea     ($0380,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #32,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z07_UpdateArrowOrBoomerang_HandleBlocked:
    jmp     HandleArrowOrBoomerangBlocked

    even
_L_z07_UpdateArrowOrBoomerang_AnimateBoomerang:
    jmp     AnimateBoomerangAndCheckCollision

    even
DrawArrow:
    ; This is an arrow. Set up sprite parameters.
    ;
    ; If facing left, set horizontal flipping in [0F].
    ;
    moveq   #0,D0
    move.b  D0,($000F,A4)
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$02,D0
    bne  _anon_z07_28
    addq.b  #1,($000F,A4)
_anon_z07_28:
    jsr     GetOppositeDir
    ; Store the weapon's frame (up or right) in [0C].
    ;
    lea     (RDirectionToWeaponFrame).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($000C,A4)
    ; Store the base sprite attribute in [04].
    ;
    lea     (RDirectionToWeaponBaseAttribute).l,A0
    move.b  (A0,D3.W),D0
    even
SetAttrAndDrawArrow:
    move.b  D0,($0004,A4)
    ; If this is a monster's arrow, add 2 to sprite attributes in [04].
    ; This chooses palette row 6.
    ;
    ; Otherwise, add the arrow item value less 1. This chooses
    ; palette row 4 if the arrow is wooden, otherwise 5 for silver.
    ;
    cmpi.b  #$0D,D2
    bcc  _L_z07_SetAttrAndDrawArrow_PlayerArrow
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$5B,D0
    bne  _L_z07_SetAttrAndDrawArrow_PlayerArrow
    move.b  ($0004,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$02,D1
    addx.b  D1,D0   ; ADC #$02 (X flag = 6502 C)
    bne  _L_z07_SetAttrAndDrawArrow_SetAttr
    even
_L_z07_SetAttrAndDrawArrow_PlayerArrow:
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0659,A4),D1
    addx.b  D1,D0   ; ADC InvArrow
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$01,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$01
    eori    #$10,CCR  ; restore X = 6502 C
    even
_L_z07_SetAttrAndDrawArrow_SetAttr:
    move.b  D0,($0004,A4)
    ; Copy the attribute to [05], and go draw.
    ;
    move.b  ($0004,A4),D0
    move.b  D0,($0005,A4)
    jmp     OffsetAndDrawArrow

    even
CheckState20:
    ; If major state <> $20, go check other states.
    ;
    cmpi.b  #$20,D0
    beq.s  __far_z_07_0089
    jmp  CheckState30
__far_z_07_0089:
    ; State $2x. Spark.
    ;
    ; Change the state to $28, and decrement animation counter.
    ; If it hasn't reached 0, then go draw and check for collision
    ; (with Link, if this is a monster's boomerang).
    ;
    ; TODO: Why state $28?
    ; I thought that it was set to $28, so that the animation frame cycle will
    ; start over again when spinning.
    ; But when animation counter reaches 0, state will be set to $40.
    ; If the counter hasn't reached 0, then I don't *think* that
    ; any drawing code depends on the minor state.
    ;
    moveq   #40,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($03D0,A4),A0
    subq.b  #1,(A0,D2.W)
    beq.s  __far_z_07_0090
    jmp  DrawArrowOrBoomerangAndCheckCollisions
__far_z_07_0090:
    ; Animation counter = 0.
    ;
    ; Set state to $40. It will become $50 below in
    ; HandleArrowOrBoomerangBlocked.
    ;
    moveq   #64,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    ; If this is an arrow (monster's or player's), then deactivate it.
    ; Else go handle the boomerang being blocked.
    ;
    cmpi.b  #$0D,D2
    bcc  _L_z07_CheckState20_CheckBoomerangBlocked
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$5B,D0
    beq  _L_z07_CheckState20_Deactivate
    even
_L_z07_CheckState20_CheckBoomerangBlocked:
    cmpi.b  #$12,D2
    beq.s  __far_z_07_0091
    jmp  HandleArrowOrBoomerangBlocked
__far_z_07_0091:
    even
_L_z07_CheckState20_Deactivate:
    jsr     ResetObjState
    ; If it's a monster's arrow, then destroy it in the monster slot,
    ; including clearing object type.
    ;
    cmpi.b  #$0D,D2
    bcc  _anon_z07_29
    jsr     DestroyCountedMonsterShot
_anon_z07_29:
    eori    #$01,CCR  ; normalize C to 6502 polarity before RTS
    rts

    even
HandleArrowOrBoomerangBlocked:
    ; Use animation counter to count down 3 screen frames in case the state is $20 (spark).
    ;
    moveq   #3,D0
    lea     ($03D0,A4),A0
    move.b  D0,(A0,D2.W)
    ; Add $10 to the state to make it $2x.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$10,D1
    addx.b  D1,D0   ; ADC #$10 (X flag = 6502 C)
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    even
DrawArrowOrBoomerangAndCheckCollisions:
    ; If the weapon is a boomerang (not a monster arrow nor player arrow),
    ; then go draw it and check for a collision.
    ;
    cmpi.b  #$0D,D2
    bcc  _L_z07_DrawArrowOrBoomerangAndCheckCollisions_DrawPlayerWeapon
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$5B,D0
    beq  _L_z07_DrawArrowOrBoomerangAndCheckCollisions_PrepareArrow
    even
_L_z07_DrawArrowOrBoomerangAndCheckCollisions_DrawPlayerWeapon:
    cmpi.b  #$12,D2
    beq  _L_z07_DrawArrowOrBoomerangAndCheckCollisions_PrepareArrow
    jmp     DrawBoomerangAndCheckCollision

    even
_L_z07_DrawArrowOrBoomerangAndCheckCollisions_PrepareArrow:
    ; Start preparing to draw an arrow.
    ;
    ; Set arrow slot frame 2 (spark) in [0C],
    ; and no horizontal flipping in [0F].
    ;
    moveq   #2,D0
    move.b  D0,($000C,A4)
    moveq   #0,D0
    move.b  D0,($000F,A4)
    ; Get reverse index of weapon's direction, and base sprite attribute 0,
    ; and go draw.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    jsr     GetOppositeDir
    moveq   #0,D0
    jmp     SetAttrAndDrawArrow

    even
CheckState30:
    ; If major state <> $30, go check other states.
    ;
    cmpi.b  #$30,D0
    bne  _L_z07_CheckState30_CheckOtherStates
    ; State $3x. Slow down.
    ;
    ; Reset grid offset for movement.
    ;
    moveq   #0,D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    ; Go slow at q-speed fraction $40 (1 pixel a frame).
    ;
    moveq   #64,D0
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    ; If facing left and X < 2, then go change state to $40. The
    ; boomerang is too close to the left edge of the screen.
    ; Another move might make it wrap around.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($000F,A4)
    andi.b #$02,D0
    beq  _L_z07_CheckState30_MoveBoomerang
    move.b  ($70,A4,D2.W),D0
    cmpi.b  #$02,D0
    bcs  _L_z07_CheckState30_SetState40
    even
_L_z07_CheckState30_MoveBoomerang:
    ; Move the boomerang.
    ;
    jsr     MoveObject
    ; Decrement timer ObjMovingLimit. Once it reaches 0, change
    ; state to $40.
    ;
    lea     ($0380,A4),A0
    subq.b  #1,(A0,D2.W)
    bne  _L_z07_CheckState30_AnimateBoomerang
    even
_L_z07_CheckState30_SetState40:
    ; Set state $40, and a time to move of $20 frames.
    ;
    ; In major state $40, ObjMovingLimit is a timer to change the state to $50.
    ;
    ; Also, animate, draw, and handle any collision (with Link, if a monster's boomerang).
    ;
    moveq   #32,D0
    lea     ($0380,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #64,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z07_CheckState30_AnimateBoomerang:
    jmp     AnimateBoomerangAndCheckCollision

    even
_L_z07_CheckState30_CheckOtherStates:
    ; State $40 or $50. Return to thrower: $40 slow, $50 fast.
    ;
    ; The boomerang will now return. Reset the grid offset.
    ;
    moveq   #0,D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    ; Get the horizontal and vertical directions and distances to the thrower.
    ;
    cmpi.b  #$0D,D2
    bcc  _anon_z07_30
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D0
_anon_z07_30:
    jsr     GetDirectionsAndDistancesToTarget
    ; If the boomerang hasn't reached the thrower ([00] < 2),
    ; then go move towards the thrower, draw, and check collisions.
    ;
    move.b  ($0000,A4),D0
    cmpi.b  #$02,D0
    bne  _L_z07_CheckState30_MoveTowardThrower
    ; The boomerang has reached the thrower.
    ;
    ; Reset the distance to move.
    ; If this is a monster's boomerang, go handle the monster catching it.
    ;
    moveq   #0,D0
    lea     ($0380,A4),A0
    move.b  D0,(A0,D2.W)
    cmpi.b  #$0D,D2
    bcs  _L_z07_CheckState30_CatchBoomerang
    ; Link has caught the boomerang.
    ;
    ; Combine Link's state with $20 for having caught the boomerang.
    ;
    ; If Link catches it some time after throwing it,
    ; his state will become $20, and he will show the catch animation.
    ;
    ; But if he catches it right after throwing it, the state becomes
    ; $30 ($10 OR $20), which is the end state of using an item.
    ;
    move.b  ($00AC,A4),D0
    ori.b #$20,D0
    move.b  D0,($00AC,A4)
    ; Make to set Link's animation counter to 1, so that he picks
    ; up the new state.
    ;
    moveq   #1,D0
    move.b  D0,($03D0,A4)
    ; Deactivate the boomerang.
    ;
    moveq   #15,D3
    moveq   #0,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D3.W)
    eori    #$01,CCR  ; normalize C to 6502 polarity before RTS
    rts

    even
_L_z07_CheckState30_CatchBoomerang:
    ; A monster caught the boomerang that it threw.
    ;
    ; Set a timer for the thrower based on a random value:
    ; < $30: $30
    ; < $70: $50
    ; Else:  $70
    ;
    moveq   #48,D3
    move.b  ($18,A4,D2.W),D0
    cmpi.b  #$30,D0
    bcs  _L_z07_CheckState30_SetThrowerTimer
    moveq   #80,D3
    cmpi.b  #$70,D0
    bcs  _L_z07_CheckState30_SetThrowerTimer
    moveq   #112,D3
    even
_L_z07_CheckState30_SetThrowerTimer:
    move.b  D3,D0
    moveq   #0,D3
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D3
    move.b  D0,($28,A4,D3.W)
    ; Reset the thrower's state to make it idle or restart its state machine.
    ; Destroy the monster's boomerang.
    ;
    moveq   #0,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D3.W)
    jmp     DestroyCountedMonsterShot

    even
_L_z07_CheckState30_MoveTowardThrower:
    ; Move towards the thrower.
    ;
    ; Middle speed index 4 goes equally fast in X and Y axes.
    ;
    moveq   #4,D3
    jsr     _CalcDiagonalSpeedIndex
    ; Move vertically towards the thrower.
    ;
    lea     (BoomerangQSpeedFracsY).l,A0
    move.b  (A0,D3.W),D0
    jsr     SetBoomerangSpeed
    move.b  ($000A,A4),D0
    move.b  D0,($000F,A4)
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D3,D0
    move.b  D0,-(A5)  ; PHA
    jsr     MoveObject
    ; Move horizontally towards the thrower.
    ;
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D3
    move.b  D0,D3
    lea     (BoomerangQSpeedFracsX).l,A0
    move.b  (A0,D3.W),D0
    jsr     SetBoomerangSpeed
    move.b  ($000B,A4),D0
    move.b  D0,($000F,A4)
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     MoveObject
    even
AnimateBoomerangAndCheckCollision:
    ; Decrement animation counter; and when it reaches 0:
    ; 1. arm it again for 2 frames
    ; 2. advance the minor state within a cycle of 8
    ; 3. see if it's time to play the sound effect, if the boomerang belongs to Link
    ;
    lea     ($03D0,A4),A0
    subq.b  #1,(A0,D2.W)
    beq.s  __far_z_07_0092
    jmp  DrawBoomerangAndCheckCollision
__far_z_07_0092:
    moveq   #2,D0
    lea     ($03D0,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$77,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    cmpi.b  #$0D,D2
    bcc.s  __far_z_07_0093
    jmp  CalcBoomerangFrame
__far_z_07_0093:
    moveq   #2,D3
    jsr     PlayBoomerangSfx
    even
DrawBoomerangAndCheckCollision:
    ; If the boomerang belongs to a monster, then check for
    ; collision with Link.
    ;
    ; If they collide, then set state $20 and animation counter 3.
    ;
    cmpi.b  #$0D,D2
    bcs.s  __far_z_07_0094
    jmp  CalcBoomerangFrame
__far_z_07_0094:
    jsr     CheckLinkCollision
    move.b  ($034B,A4),D0
    bne.s  __far_z_07_0095
    jmp  CalcBoomerangFrame
__far_z_07_0095:
    moveq   #3,D0
    lea     ($03D0,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #32,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    even
CalcBoomerangFrame:
    ; The minor state (low 3 bits of state) is used to
    ; set the right frame in [0C] for this point in the spinning cycle.
    ;
    ; Reset [00] and [01]. These are the offsets for boomerang's position.
    ; In other words, don't offset the coordinate below.
    ;
    moveq   #0,D0
    move.b  D0,($0000,A4)
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    moveq   #0,D3
    move.b  D0,D3
    moveq   #0,D0
    move.b  D0,($0001,A4)
    lea     (BoomerangFrameCycle).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($000C,A4)
    ; Store the base sprite attribute for this point in the cycle in [04].
    ;
    move.b  D3,D0
    lea     (BoomerangBaseSpriteAttrCycle).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0004,A4)
    ; TODO: ?
    ; If base sprite attribute in [04] = 8, then leave [04] as it is.
    ; Else add the item value of the magic boomerang.
    ;
    ; But none of the values in the base sprite attributes array is 8.
    ;
    ; As far I can tell, the magic boomerang's item value (0 or 1) in
    ; the inventory will always be added to the base sprite attribute.
    ;
    ; So, palette row 4 or 5 will be chosen.
    ;
    moveq   #0,D3
    cmpi.b  #$08,D0
    beq  _anon_z07_31
    moveq   #0,D3
    move.b  ($0675,A4),D3
_anon_z07_31:
    move.b  D3,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0004,A4),D1
    addx.b  D1,D0   ; ADC $04
    move.b  D0,($0004,A4)
    moveq   #29,D3
    jmp     L_DrawArrowOrBoomerang

; Params:
; Y: reverse direction index that the weapon is facing
;
;
; [00] and [01] will hold sprite X and Y.
; Begin with the horizontal and vertical offsets.
;
    even
OffsetAndDrawArrow:
    lea     (RDirectionToOffsetsX).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0000,A4)
    lea     (RDirectionToOffsetsY).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0001,A4)
    moveq   #2,D3
    even
L_DrawArrowOrBoomerang:
    ; Add the weapon's true coordinates to offsets in [00] and [01].
    ;
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0000,A4),D1
    addx.b  D1,D0   ; ADC $00
    move.b  D0,($0000,A4)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0001,A4),D1
    addx.b  D1,D0   ; ADC $01
    move.b  D0,($0001,A4)
    ; If state = $2x (spark), use palette row 5 to write sprites.
    ; Otherwise, use the sprite attributes we already calculated.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$F0,D0
    cmpi.b  #$20,D0
    bne  _L_z07_L_DrawArrowOrBoomerang_Draw
    moveq   #1,D0
    jsr     Anim_SetSpriteDescriptorAttributes
    even
_L_z07_L_DrawArrowOrBoomerang_Draw:
    jmp     Anim_WriteItemSprites

    even
UpdateRodOrArrow:
    ; The rod uses states $3x. Arrow uses $1x and $2x.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$F0,D0
    cmpi.b  #$30,D0
    bcs.s  __far_z_07_0096
    jmp  UpdateSwordOrRod
__far_z_07_0096:
    jmp     UpdateArrowOrBoomerang

; 4 sets of horizontal offsets, one for each state of weapon.
; Each set contains 4 offsets in reverse direction index order:
; up, down, left, right
;
; These offsets are added to player X to get weapon X.
;
    even
PlayerToWeaponOffsetsX:
    dc.b    $FF, $01, $00, $F8, $FF, $01, $F5, $0B
    dc.b    $FF, $01, $F9, $07, $FF, $01, $FD, $03

; 4 sets of vertical offsets, one for each state of weapon.
; Each set contains 4 offsets in reverse direction index order:
; up, down, left, right
;
; These offsets are added to player Y to get weapon Y.
;
    even
PlayerToWeaponOffsetsY:
    dc.b    $F7, $F2, $F5, $F5, $F6, $0D, $03, $03
    dc.b    $F7, $09, $03, $03, $FF, $05, $03, $03

    even
UpdateSwordOrRod:
    ; If state = 0, the object is not active. So, return.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    beq  _L_z07_UpdateSwordOrRod_Exit
    ; Decrement the state timer.
    ; If it hasn't expired, go move the sword or rod.
    ;
    lea     ($03D0,A4),A0
    subq.b  #1,(A0,D2.W)
    bne  _L_z07_UpdateSwordOrRod_DrawSwordOrRod
    ; State 2 will last 8 frames. The higher ones last 1.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    moveq   #0,D3
    move.b  D0,D3
    moveq   #8,D0
    subq.b  #1,D3
    beq  _anon_z07_32
    moveq   #1,D0
_anon_z07_32:
    ; Set both the player's animation counter and the sword's
    ; animation counter/timer to this value.
    ;
    move.b  D0,($03D0,A4)
    lea     ($03D0,A4),A0
    move.b  D0,(A0,D2.W)
    ; Go to the next state.
    ;
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    ; Once we reach state 6, deactivate the object.
    ; Otherwise, go draw it.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    cmpi.b  #$06,D0
    bcs  _L_z07_UpdateSwordOrRod_DrawSwordOrRod
    jsr     ResetObjState
    even
_L_z07_UpdateSwordOrRod_Exit:
    rts

    even
_L_z07_UpdateSwordOrRod_DrawSwordOrRod:
    ; Reset horizontal flipping in [0F].
    ;
    moveq   #0,D0
    move.b  D0,($000F,A4)
    ; If state = 5, return without drawing.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    moveq   #0,D3
    move.b  D0,D3
    move.b  #$FC,D0
    cmpi.b  #$05,D3
    beq  _L_z07_UpdateSwordOrRod_Exit
    even
_L_z07_UpdateSwordOrRod_Add4:
    ; Set [00] to (state - 1) * 4:
    ; the byte offset of the beginning of a set of pixel offsets.
    ;
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$04,D1
    addx.b  D1,D0   ; ADC #$04 (X flag = 6502 C)
    subq.b  #1,D3
    bne  _L_z07_UpdateSwordOrRod_Add4
    move.b  D0,($0000,A4)
    ; Set object's direction to player's. It might have changed
    ; since the last frame.
    ;
    move.b  ($0098,A4),D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; Add [00] and the reverse index of the direction to get
    ; the byte offset of the pixel offset.
    ;
    jsr     GetOppositeDir
    move.b  D3,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0000,A4),D1
    addx.b  D1,D0   ; ADC $00
    moveq   #0,D3
    move.b  D0,D3
    ; Set object's X to player's X + offset for state and direction.
    ; Copy the result to [00].
    ;
    move.b  ($0070,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (PlayerToWeaponOffsetsX).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC PlayerToWeaponOffsetsX,Y
    move.b  D0,($70,A4,D2.W)
    move.b  D0,($0000,A4)
    ; Set object's Y to player's Y + offset for state and direction.
    ; Copy the result to [01].
    ;
    move.b  ($0084,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (PlayerToWeaponOffsetsY).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC PlayerToWeaponOffsetsY,Y
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D0,($0001,A4)
    ; If state = 1, use up direction.
    ; Else use object direction.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    moveq   #0,D3
    move.b  D0,D3
    moveq   #8,D0
    subq.b  #1,D3
    beq  _L_z07_UpdateSwordOrRod_CalcAttrs
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    even
_L_z07_UpdateSwordOrRod_CalcAttrs:
    ; Store the weapon's frame (horizontal or vertical)
    ; for the direction chosen above in [0C].
    ;
    jsr     GetOppositeDir
    lea     (RDirectionToWeaponFrame).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($000C,A4)
    ; Calculate sprite attributes.
    ;
    ; If the weapon is the rod, calculate its sprite attributes:
    ;   base attribute OR 1
    ; So, it uses palette row 5.
    ;
    lea     (RDirectionToWeaponBaseAttribute).l,A0
    move.b  (A0,D3.W),D0
    cmpi.b  #$0D,D2
    beq  _L_z07_UpdateSwordOrRod_CalcSwordAttrs
    ori.b #$01,D0
    jmp     _L_z07_UpdateSwordOrRod_SetAttrs

    even
_L_z07_UpdateSwordOrRod_CalcSwordAttrs:
    ; The weapon is the sword.
    ; To calculate the sprite attributes: (item value - 1) + base attribute
    ;
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0657,A4),D1
    addx.b  D1,D0   ; ADC Items
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$01,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$01
    eori    #$10,CCR  ; restore X = 6502 C
    even
_L_z07_UpdateSwordOrRod_SetAttrs:
    ; Set sprite attributes to the calculated value above.
    ;
    jsr     Anim_SetSpriteDescriptorAttributes
    ; If the direction is left, set [0F] to flip horizontally.
    ;
    cmpi.b  #$02,D3
    bne  _anon_z07_33
    addq.b  #1,($000F,A4)
_anon_z07_33:
    ; If state = 1, return. Don't show the weapon.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    cmpi.b  #$01,D0
    bne.s  __far_z_07_0097
    jmp  L1F854_Exit
__far_z_07_0097:
    ; Set Y to the right item slot to pass to the routine to write sprites:
    ; sword or rod
    ;
    ;
    ; Sword slot
    moveq   #0,D3
    cmpi.b  #$0D,D2
    beq  _anon_z07_34
    moveq   #8,D3
_anon_z07_34:
    jsr     Anim_WriteItemSprites
    ; If state <> 3, return.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    cmpi.b  #$03,D0
    beq.s  __far_z_07_0098
    jmp  L1F854_Exit
__far_z_07_0098:
    ; State = 3. Time to instantiate a shot.
    ;
    ; If object slot is not the rod's, go instantiate the sword shot separately.
    ;
    cmpi.b  #$12,D2
    beq.s  __far_z_07_0099
    jmp  MakeSwordShot
__far_z_07_0099:
    ; Instantiate a magic shot (rod shot).
    ; Switch to the shot slot $E.
    ;
    moveq   #14,D2
    ; If high bit of state is set, return. It's already active.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z07_UpdateSwordOrRod_MakeMagicShot
    lsl.b  #1,D0   ; ASL A
    bcc.s  __far_z_07_0100
    jmp  L1F854_Exit
__far_z_07_0100:
    even
_L_z07_UpdateSwordOrRod_MakeMagicShot:
    ; Play "magic shot" tune.
    ;
    moveq   #4,D0
    move.b  D0,($0604,A4)
    ; Activate the shot object (state $80).
    ;
    move.b  #$80,D0
    even
SetUpWeaponWithState:
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #16,D0
    jsr     PlaceWeapon
    ; If the direction is horizontal, and X < $14 or >= $EC, then
    ; deactivate the shot object.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$03,D0
    beq  _L_z07_SetUpWeaponWithState_ChooseSpeed
    move.b  ($70,A4,D2.W),D0
    cmpi.b  #$14,D0
    bcc.s  __far_z_07_0101
    jmp  ResetObjState
__far_z_07_0101:
    cmpi.b  #$EC,D0
    bcs.s  __far_z_07_0102
    jmp  ResetObjState
__far_z_07_0102:
    even
_L_z07_SetUpWeaponWithState_ChooseSpeed:
    ; If high bit of state is set, use $A0 else $C0 for the q-speed fraction.
    ;
    ; The high bit is set for magic shot, and reset for sword shot.
    ;
    move.b  #$C0,D3
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    lsl.b  #1,D0   ; ASL A
    bcc  _anon_z07_35
    move.b  #$A0,D3
_anon_z07_35:
    move.b  D3,D0
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set the shot object's grid offset the same as the player's.
    ;
    move.b  ($0394,A4),D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    even
L1F854_Exit:
    rts

; Returns:
; A: 0
;
; If it's the room item, then deactivates it.
;
    even
ResetObjState:
    moveq   #0,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
MakeSwordShot:
    ; Try to activate a sword shot.
    ;
    ; Switch to shot slot $E.
    ;
    moveq   #14,D2
    ; If state <> 0, return. It's already activated.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    beq.s  __far_z_07_0103
    jmp  L1F854_Exit
__far_z_07_0103:
    ; If [0529] is set, go activate a sword shot regardless of hearts.
    ;
    ; TODO: But is this used?
    ;
    move.b  ($0529,A4),D0
    bne  _L_z07_MakeSwordShot_SetUp
    ; If full hearts <> (heart containers - 1), return.
    ;
    move.b  ($066F,A4),D0
    move.b  D0,-(A5)  ; PHA
    andi.b #$0F,D0
    move.b  D0,($0000,A4)
    move.b  (A5)+,D0  ; PLA
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    move.b  ($0000,A4),D1
    cmp.b   D1,D0
    beq.s  __far_z_07_0104
    jmp  L1F854_Exit
__far_z_07_0104:
    ; If partial heart is less than half full, return.
    ;
    move.b  ($0670,A4),D0
    cmpi.b  #$80,D0
    bcc.s  __far_z_07_0105
    jmp  L1F854_Exit
__far_z_07_0105:
    even
_L_z07_MakeSwordShot_SetUp:
    moveq   #1,D0
    jsr     PlaySample
    ; Go finish setting up a sword shot in initial state $10.
    ;
    moveq   #16,D0
    beq.s  __far_z_07_0106
    jmp  SetUpWeaponWithState
__far_z_07_0106:
    even
UpdateFire:
    ; If this is not a walking fire (state $21), skip moving it.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$21,D0
    bne  _L_z07_UpdateFire_StandingFie
    ; Move as if grid offset were 0.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    moveq   #0,D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($000F,A4)
    jsr     MoveObject
    move.b  (A5)+,D0  ; PLA
    ; Add grid offset after the move to the original.
    ; This makes it continuous, and useful as a distance traveled.
    ;
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC ObjGridOffset,X
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    ; If the absolute value of grid offset < $10, go draw.
    ; 
    ; Once the absolute value of grid offset = $10,
    ; make the fire stand instead of move.
    ; Set state $22 and last $3F frames.
    ;
    jsr     Abs
    cmpi.b  #$10,D0
    bne  _L_z07_UpdateFire_DrawAndCheckCollisions
    moveq   #63,D0
    move.b  D0,($28,A4,D2.W)
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    even
_L_z07_UpdateFire_StandingFie:
    ; Check a standing fire.
    ;
    ; If time has run out, deactivate the item and return.
    ;
    move.b  ($28,A4,D2.W),D0
    bne.s  __far_z_07_0107
    jmp  ResetObjState
__far_z_07_0107:
    ; If in UW, update the candle to brighten the room if needed.
    ;
    move.b  ($0010,A4),D0
    beq  _L_z07_UpdateFire_DrawAndCheckCollisions
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    moveq   #4,D0
    jsr     SwitchBank
    jsr     UpdateCandle
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    even
_L_z07_UpdateFire_DrawAndCheckCollisions:
    ; Advance the animation counter, and draw.
    ;
    ;
    ; 4 frames in every animation cycle.
    moveq   #4,D0
    jsr     Anim_AdvanceAnimCounterAndSetObjPosForSpriteDescriptor
    jsr     Anim_SetObjHFlipForSpriteDescriptor
    jsr     Anim_SetSpriteDescriptorRedPaletteRow
    moveq   #0,D0
    move.b  D0,($000C,A4)
    moveq   #64,D3
    jsr     DrawObjectWithType
    ; Now check for a collision with the player.
    ;
    ; First, if the player is invincible, return.
    ;
    move.b  ($04F0,A4),D0
    beq.s  __far_z_07_0108
    jmp  L1F91D_Exit
__far_z_07_0108:
    ; Save the object index in [00].
    ;
    move.b  D2,($0000,A4)
    ; Store the player's center point coordinates in [04] and [05].
    ;
    moveq   #0,D2
    moveq   #2,D3
    jsr     GetWideObjectMiddle
    ; Store the fire's center point coordinates in [02] and [03].
    ;
    moveq   #0,D2
    move.b  ($0000,A4),D2
    moveq   #0,D3
    jsr     GetWideObjectMiddle
    ; If the objects don't collide (< $E pixels in X and Y), then return.
    ;
    moveq   #0,D3
    move.b  ($0000,A4),D3
    moveq   #0,D2
    moveq   #14,D0
    jsr     DoObjectsCollide
    bne.s  __far_z_07_0109
    jmp  L1F91D_Exit
__far_z_07_0109:
    ; The player and the fire collide.
    ;
    ; Make the fire shove the player.
    ;
    moveq   #0,D2
    move.b  ($0000,A4),D2
    moveq   #0,D3
    move.b  D3,($0000,A4)
    jsr     BeginShove
    ; Harm the player $80 points.
    ;
    moveq   #0,D0
    move.b  D0,($000D,A4)
    move.b  #$80,D0
    move.b  D0,($000E,A4)
    jmp     Link_BeHarmed

; Params:
; X: object index
; Y: offset from [02] and [03] to store center X and Y
;
; Returns:
; [02 + Y]: center X
; [03 + Y]: center Y
;
    even
GetWideObjectMiddle:
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($02,A4,D3.W)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($03,A4,D3.W)
    even
L1F91D_Exit:
    rts

    even
BombTimes:
    dc.b    $30, $18, $0C, $06

    even
BombableWallHotspotsX:
    dc.b    $78, $78, $20, $D0

    even
BombableWallHotspotsY:
    dc.b    $5D, $BD, $8D, $8D

    even
UpdateBombOrFire:
    ; If the object's not active, return.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    bne.s  __far_z_07_0110
    jmp  L1F95F_Exit
__far_z_07_0110:
    ; Bomb major state = $10. Fire major state = $20.
    ;
    andi.b #$F0,D0
    cmpi.b  #$10,D0
    bne.s  __far_z_07_0111
    jmp  UpdateBomb
__far_z_07_0111:
    jmp     UpdateFire

    even
UpdateBomb:
    ; This is a bomb.
    ;
    ; If the timer has not expired, then go draw.
    ;
    move.b  ($28,A4,D2.W),D0
    beq.s  __far_z_07_0112
    jmp  DrawBomb
__far_z_07_0112:
    ; The timer has expired. Set another based on the minor state.
    ; Advance the state.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (BombTimes-1).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($28,A4,D2.W)
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    ; If the minor state = 3, play the sound effect.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    move.b  D0,-(A5)  ; PHA
    cmpi.b  #$03,D0
    bne  _L_z07_UpdateBomb_CheckState5
    moveq   #16,D0
    jsr     PlayEffect
    even
_L_z07_UpdateBomb_CheckState5:
    move.b  (A5)+,D0  ; PLA
    ; If minor state = 5, then deactivate the bomb, and return.
    ;
    cmpi.b  #$05,D0
    beq.s  __far_z_07_0113
    jmp  Bomb_CheckState4
__far_z_07_0113:
    jsr     ResetObjState
    move.b  D0,($28,A4,D2.W)
    even
L1F95F_Exit:
    rts

    even
Bomb_CheckState4:
    ; If minor state <> 4, go draw.
    ;
    cmpi.b  #$04,D0
    beq.s  __far_z_07_0114
    jmp  DrawBomb
__far_z_07_0114:
    ; Minor state = 4. Try to break a wall.
    ;
    ; If in OW, go draw. Rock walls have a tile object that checks for bombs.
    ;
    move.b  ($0010,A4),D0
    bne.s  __far_z_07_0115
    jmp  DrawBomb
__far_z_07_0115:
    ; Bombs don't blast walls in cellars (mode 9). Go draw.
    ;
    move.b  ($0012,A4),D0
    cmpi.b  #$09,D0
    bne.s  __far_z_07_0116
    jmp  DrawBomb
__far_z_07_0116:
    ; We're in UW. See if the bomb is near a bombable wall.
    ;
    moveq   #4,D3
    even
_L_z07_Bomb_CheckState4_LoopHotspot:
    subq.b  #1,D3
    bpl.s  __far_z_07_0117
    jmp  DrawBomb
__far_z_07_0117:
    ; If the bomb's X is not within $18 pixels of the hotspot, then
    ; go check the next hotspot.
    ;
    lea     (BombableWallHotspotsX).l,A0
    move.b  (A0,D3.W),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($70,A4,D2.W),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC ObjX,X
    eori    #$10,CCR  ; restore X = 6502 C
    jsr     Abs
    cmpi.b  #$18,D0
    bcc  _L_z07_Bomb_CheckState4_LoopHotspot
    ; If the bomb's Y is not within $18 pixels of the hotspot, then
    ; go check the next hotspot.
    ;
    lea     (BombableWallHotspotsY).l,A0
    move.b  (A0,D3.W),D0
    ori     #$11,CCR  ; SEC: set C+X
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC ObjY,X
    eori    #$10,CCR  ; restore X = 6502 C
    jsr     Abs
    cmpi.b  #$18,D0
    bcc  _L_z07_Bomb_CheckState4_LoopHotspot
    ; Store in [02] the direction corresponding to the hotspot's index.
    ;
    lea     (ReverseDirections).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0002,A4)
    ; If it was already opened or triggered, then go draw.
    ;
    move.b  ($00EE,A4),D1
    and.b  D1,D0
    beq.s  __far_z_07_0118
    jmp  DrawBomb
__far_z_07_0118:
    move.b  ($0054,A4),D0
    beq.s  __far_z_07_0119
    jmp  DrawBomb
__far_z_07_0119:
    ; If it's not a bombable wall, go draw.
    ;
    moveq   #5,D0
    jsr     SwitchBank
    jsr     FindDoorAttrByDoorBit
    cmpi.b  #$04,D0
    beq.s  __far_z_07_0120
    jmp  DrawBomb
__far_z_07_0120:
    ; Trigger this bombable wall to open.
    ;
    moveq   #6,D0
    move.b  D0,($0054,A4)
    move.b  ($0002,A4),D0
    move.b  D0,($0055,A4)
    even
DrawBomb:
    ; Draw the bomb or dust cloud.
    ;
    jsr     Anim_FetchObjPosForSpriteDescriptor
    jsr     DrawBombOrCloudAt
    ; If minor state = 2, we drew a bomb. So, return.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    cmpi.b  #$02,D0
    bne.s  __far_z_07_0121
    jmp  L1F95F_Exit
__far_z_07_0121:
    ; Otherwise, we drew one dust cloud. Go draw the others.
    ;
    jmp     DrawOtherBombClouds

; Params:
; X: object index
; [00]: X
; [01]: Y
;
    even
DrawBombOrCloudAt:
    jsr     UpdateBombFlashEffect
; Params:
; X: object index
; [00]: X
; [01]: Y
;
;
; Set frame image = minor state - 2.
;
    even
DrawBombOrCloudNoFlashing:
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$02,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$02
    eori    #$10,CCR  ; restore X = 6502 C
; Params:
; A: frame image (1 to 3)
; X: object index
; [00]: X
; [01]: Y
;
;
; [0C] frame image
    even
DrawCloud:
    move.b  D0,($000C,A4)
    moveq   #0,D3
    move.b  D3,($000F,A4)
    ; Write sprites with blue sprite palette row and bomb item slot.
    ;
    addq.b  #1,D3
    move.b  D3,($0004,A4)
    move.b  D3,($0005,A4)
    moveq   #1,D3
    jmp     Anim_WriteItemSprites

    even
BombCloudOffsetsY1:
    dc.b    $F3, $00, $0E

    even
BombCloudOffsetsX1:
    dc.b    $F9, $0E, $07

    even
BombCloudOffsetsY2:
    dc.b    $F3, $00, $0E

    even
BombCloudOffsetsX2:
    dc.b    $07, $F3, $F9

    even
DrawOtherBombClouds:
    ; For each of 3 clouds, indexed by Y register:
    ;
    moveq   #2,D3
    even
_L_z07_DrawOtherBombClouds_LoopCloud:
    move.b  D3,D0
    move.b  D0,-(A5)  ; PHA
    ; Every other screen frame, add 6 to the index to point inside
    ; the second set of coordinates.
    ;
    move.b  ($0015,A4),D0
    lsr.b  #1,D0   ; LSR A
    bcc  _L_z07_DrawOtherBombClouds_Draw
    move.b  D3,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$06,D1
    addx.b  D1,D0   ; ADC #$06 (X flag = 6502 C)
    moveq   #0,D3
    move.b  D0,D3
    even
_L_z07_DrawOtherBombClouds_Draw:
    ; Set [01] to cloud position (object Y + Y offset).
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (BombCloudOffsetsY1).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC BombCloudOffsetsY1,Y
    move.b  D0,($0001,A4)
    ; Set [00] to cloud position (object X + X offset).
    ;
    move.b  ($70,A4,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (BombCloudOffsetsX1).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC BombCloudOffsetsX1,Y
    move.b  D0,($0000,A4)
    ; Draw the cloud at this position.
    ;
    jsr     DrawBombOrCloudNoFlashing
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D3
    move.b  D0,D3
    ; Loop while >= 0.
    ;
    subq.b  #1,D3
    bpl  _L_z07_DrawOtherBombClouds_LoopCloud
    rts

    even
AnimateAndDrawMetaObject:
    jsr     Anim_FetchObjPosForSpriteDescriptor
    ; If the metastate >= $10, go animate and draw the death sparkle.
    ;
    lea     ($0405,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$10,D0
    bcc  _L_z07_AnimateAndDrawMetaObject_AnimateSpark
    ; Animate and draw the spawning cloud.
    ;
    andi.b #$0F,D0
    jsr     DrawCloud
    even
_L_z07_AnimateAndDrawMetaObject_CheckMetaObjTimer:
    ; If the object's timer has expire, then go to the next metastate
    ; and last 6 frames.
    ;
    move.b  ($28,A4,D2.W),D0
    bne  _L_z07_AnimateAndDrawMetaObject_Exit
    even
_L_z07_AnimateAndDrawMetaObject_IncMetastate:
    moveq   #6,D0
    move.b  D0,($28,A4,D2.W)
    lea     ($0405,A4),A0
    addq.b  #1,(A0,D2.W)
    even
_L_z07_AnimateAndDrawMetaObject_Exit:
    rts

    even
_L_z07_AnimateAndDrawMetaObject_AnimateSpark:
    ; If metastate = $10, then go increment metastate and set
    ; object timer without drawing.
    ;
    andi.b #$0F,D0
    beq  _L_z07_AnimateAndDrawMetaObject_IncMetastate
    ; Set the frame image in [0C] (1, 0, 1) for the metastate.
    ;
    andi.b #$01,D0
    move.b  D0,($000C,A4)
    moveq   #1,D0
    jsr     Anim_SetSpriteDescriptorAttributes
    moveq   #36,D3
    jsr     Anim_WriteItemSprites
    jmp     _L_z07_AnimateAndDrawMetaObject_CheckMetaObjTimer

; Returns:
; Y: animation frame
; [00]: object X
; [01]: object Y
; [0F]: flip horizontally
;
    even
AnimateLinkBase:
    move.b  ($00AC,A4),D0
    beq.s  __far_z_07_0122
    jmp  AnimateObjectWalking
__far_z_07_0122:
    move.b  ($0012,A4),D0
    cmpi.b  #$04,D0
    bne.s  __far_z_07_0123
    jmp  AnimateObjectWalking
__far_z_07_0123:
    cmpi.b  #$10,D0
    bne.s  __far_z_07_0124
    jmp  AnimateObjectWalking
__far_z_07_0124:
    move.b  ($03F8,A4),D0
    bne.s  __far_z_07_0125
    jmp  SetUpWalkingSprites
__far_z_07_0125:
; Params:
; X: object index
;
; Returns:
; Y: animation frame
; [00]: object X
; [01]: object Y
; [0F]: flip horizontal
;
; As the object walks, the animation counter rolls down.
;
    even
AnimateObjectWalking:
    lea     ($03D0,A4),A0
    subq.b  #1,(A0,D2.W)
    beq.s  __far_z_07_0126
    jmp  SetUpWalkingSprites
__far_z_07_0126:
    ; Once the counter reaches 0, and if object is the player,
    ; animate Link's object state.
    ;
    cmpi.b  #$00,D2
    bne  _anon_z07_36
    jsr     AnimateLinkObjState
_anon_z07_36:
    ; Roll over the counter (6 frames).
    ;
    moveq   #6,D0
    move.b  D0,($0000,A4)
    jsr     RollOverAnimCounter
    even
SetUpWalkingSprites:
    ; Set up sprite position in the descriptors.
    ;
    jsr     Anim_FetchObjPosForSpriteDescriptor
    ; Set up horizontal flipping.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0C,D0
    bne.s  __far_z_07_0127
    jmp  SetUpHorizontalWalkingSprites
__far_z_07_0127:
    ; Facing up or down.
    ;
    ;
    ; Assume animation frame 3 (up).
    moveq   #3,D3
    andi.b #$08,D0
    beq.s  __far_z_07_0128
    jmp  Anim_SetObjHFlipForSpriteDescriptor
__far_z_07_0128:
    subq.b  #1,D3
; Use the movement frame as the value for horizontal flipping.
;
; Params:
; X: object index
;
; Returns:
; [0F]: flip horizontal, based on ObjMovementFrame
;
    even
Anim_SetObjHFlipForSpriteDescriptor:
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($000F,A4)
    rts

    even
SetUpHorizontalWalkingSprites:
    ; Facing left or right.
    ;
    ;
    ; Assume animation frame 0 (legs apart).
    moveq   #0,D3
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D0
    beq  _anon_z07_37
    addq.b  #1,D3
_anon_z07_37:
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$01,D0
    bne  _anon_z07_38
    addq.b  #1,($000F,A4)
_anon_z07_38:
    rts

; Params:
; A: new value for animation counter, in case it rolls over
; X: object index
;
; Returns:
; A: 0
; [00]: X
; [01]: Y
; [0F]: 0 for no horizontal flipping
;
    even
Anim_AdvanceAnimCounterAndSetObjPosForSpriteDescriptor:
    move.b  D0,($0000,A4)
    lea     ($03D0,A4),A0
    subq.b  #1,(A0,D2.W)
    beq.s  __far_z_07_0129
    jmp  Anim_FetchObjPosForSpriteDescriptor
__far_z_07_0129:
    jsr     RollOverAnimCounter
; Params:
; X: object index
;
; Returns:
; A: 0
; [00]: X
; [01]: Y
; [0F]: 0 for no horizontal flipping
;
    even
Anim_FetchObjPosForSpriteDescriptor:
    move.b  ($70,A4,D2.W),D0
    move.b  D0,($0000,A4)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0001,A4)
    moveq   #0,D0
    move.b  D0,($000F,A4)
    rts

; Roll over the animation counter, and switch the movement frame.
;
; Params:
; [00]: new counter value
;
    even
RollOverAnimCounter:
    move.b  ($0000,A4),D0
    lea     ($03D0,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($03E4,A4),A0
    move.b  (A0,D2.W),D0
    eori.b #$01,D0
    lea     ($03E4,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
AnimateLinkObjState:
    ; If major state = $10
    ;   if minor state = 0, make it 1
    ;   else OR state with $30
    ;   go set movement frame to 1
    ;
    move.b  ($00AC,A4),D0
    andi.b #$30,D0
    cmpi.b  #$10,D0
    bne  _L_z07_AnimateLinkObjState_CheckState20
    move.b  ($00AC,A4),D0
    andi.b #$0F,D0
    bne  _L_z07_AnimateLinkObjState_CombineStateWith30
    beq  _L_z07_AnimateLinkObjState_IncState
    even
_L_z07_AnimateLinkObjState_CheckState20:
    ; If major state = $20
    ;   if minor state = 0, make it 1
    ;   else OR state with $30
    ;   go set movement frame to 1
    ;
    cmpi.b  #$20,D0
    bne  _L_z07_AnimateLinkObjState_CheckState30
    move.b  ($00AC,A4),D0
    andi.b #$0F,D0
    bne  _L_z07_AnimateLinkObjState_CombineStateWith30
    even
_L_z07_AnimateLinkObjState_IncState:
    addq.b  #1,($00AC,A4)
    jmp     _L_z07_AnimateLinkObjState_SetMovementFrame1

    even
_L_z07_AnimateLinkObjState_CombineStateWith30:
    move.b  ($00AC,A4),D0
    ori.b #$30,D0
    move.b  D0,($00AC,A4)
    even
_L_z07_AnimateLinkObjState_SetMovementFrame1:
    ; To animate the state, the animation counter had to have
    ; reached 0. Right after this routine, the counter will be
    ; rolled over, and the movement frame will be switched.
    ;
    ; So, set movement frame to 1 (legs together) at the end of
    ; the animation here, in order to immediately change it to
    ; 0 (legs apart) after this.
    ;
    moveq   #1,D0
    move.b  D0,($03E4,A4)
    rts

    even
_L_z07_AnimateLinkObjState_CheckState30:
    ; If in state $30, then make Link idle, except for halting.
    ;
    cmpi.b  #$30,D0
    bne  _anon_z07_39
    move.b  ($00AC,A4),D0
    andi.b #$C0,D0
    move.b  D0,($00AC,A4)
_anon_z07_39:
    eori    #$01,CCR  ; normalize C to 6502 polarity before RTS
    rts

