UpdateObject:
    move.b  D0,-(A5)  ; PHA
    moveq   #4,D0
    jsr     SwitchBank
    move.b  (A5)+,D0  ; PLA
    ; If the object was initialized, go update it.
    ;
    moveq   #0,D3
    lea     ($0492,A4),A0
    move.b  (A0,D2.W),D3
    move.b  D3,($000F,A4)
    beq  _L_z07_UpdateObject_Update
    ; If the object type starts with a spawning cloud
    ; (type < $53, except armos and flying ghini),
    ; then set object timer to 7.
