    ; But this will be overridden during initialization.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$1E,D0
    beq  _L_z07_UpdateObject_Init
    cmpi.b  #$22,D0
