UpdateMetaObject:
    jsr     AnimateAndDrawMetaObject
    ; Go handle end metastates (4 and $14) specially.
    ;
    lea     ($0405,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    cmpi.b  #$04,D0
    bcs.s  __far_z_07_0130
    jmp  UpdateMetaObjectEnd
__far_z_07_0130:
    even
DoNothing:
    rts

    even
UpdateMetaObjectEnd:
    ; Metastate = 4 or $14.
    ;
    ; If it's 4, go reset the metastate. The object is ready to update
    ; on its own.
    ;
    lea     ($0405,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$10,D0
    beq  _L_z07_UpdateMetaObjectEnd_Reset
    ; Metastate = $14
    ;
    ; Copy the object type, so that it can be used in setting up
    ; a dropped item.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    lea     ($0412,A4),A0
    move.b  D0,(A0,D2.W)
    ; Certain objects don't advance the world kill cycle.
    ;
    cmpi.b  #$5D,D0
    beq  _L_z07_UpdateMetaObjectEnd_DropItem
    cmpi.b  #$14,D0
    beq  _L_z07_UpdateMetaObjectEnd_DropItem
    cmpi.b  #$1C,D0
    beq  _L_z07_UpdateMetaObjectEnd_DropItem
