    ;
    move.b  ($052A,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    cmpi.b  #$0A,D0
    bne  _anon_z07_41
    moveq   #0,D0
_anon_z07_41:
    move.b  D0,($052A,A4)
