    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$11,D0
    beq  _L_z07_UpdateMetaObjectEnd_DropItem
    addq.b  #1,($034F,A4)
    even
_L_z07_UpdateMetaObjectEnd_DropItem:
