    ;
    moveq   #96,D0
    lea     ($034F,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0492,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  #$81,D0
    lea     ($04BF,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     SetUpDroppedItem
