InitObject:
    moveq   #0,D2
    move.b  ($0340,A4),D2
    ; We want to handle "enemies from the edges of the screen".
    ;
    ; So, if not in UW, or "enemies from edges" attribute is clear,
    ; or the object is (zora, fire, armos, whirlwind), or any object
    ; that does not spawn with a cloud (type >= $53);
    ; 
    ; then go initialize the object.
    ;
    move.b  ($0010,A4),D0
    bne  _L_z07_InitObject_NormalSpawn
    move.b  ($04CD,A4),D0
    andi.b #$08,D0
    beq  _L_z07_InitObject_NormalSpawn
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$11,D0
    beq  _L_z07_InitObject_NormalSpawn
    cmpi.b  #$40,D0
    beq  _L_z07_InitObject_NormalSpawn
    cmpi.b  #$1E,D0
    beq  _L_z07_InitObject_NormalSpawn
    cmpi.b  #$2E,D0
    beq  _L_z07_InitObject_NormalSpawn
    cmpi.b  #$53,D0
    bcc  _L_z07_InitObject_NormalSpawn
    even
_L_z07_InitObject_UninitMonsterFromEdge:
    ; If the "monsters from edges" long timer expired, then
    ; go bring the monster in.
    ; Else revert the flag, so this monster becomes uninitialized.
    ;
    move.b  ($004B,A4),D0
    beq  _L_z07_InitObject_InitMonsterFromEdge
    lea     ($0492,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
_L_z07_InitObject_InitMonsterFromEdge:
    moveq   #0,D2
    move.b  ($0340,A4),D2
    moveq   #5,D0
    jsr     SwitchBank
    jsr     FindNextEdgeSpawnCell
    ; Extract and set the monster's location.
    ;
    move.b  ($0525,A4),D0
    ; Square column in low nibble. Multiply by 16 to get X.
    ;
    move.b  D0,-(A5)  ; PHA
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    move.b  D0,($70,A4,D2.W)
    ; Square row in high nibble. Subtract 3, for the usual offset, to get Y.
    ;
    move.b  (A5)+,D0  ; PLA
    andi.b #$F0,D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$03,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$03
    eori    #$10,CCR  ; restore X = 6502 C
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set the monsters-from-edges long timer to a random value
    ; between 2 and 5. So, it will last 20 to 50 frames.
    ;
    move.b  ($19,A4,D2.W),D0
    andi.b #$03,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$02,D1
    addx.b  D1,D0   ; ADC #$02 (X flag = 6502 C)
    move.b  D0,($004B,A4)
    ; If the distance to Link is too close to Link, then
    ; go flag the monster uninitialized again, so we can
    ; try to spawn it again next time.
    ;
    moveq   #5,D0
    jsr     SwitchBank
    jsr     IsDistanceSafeToSpawn
    bcs  _L_z07_InitObject_UninitMonsterFromEdge
    ; OK to spawn.
    ; In this situation, monsters don't spawn from a cloud.
    ;
    moveq   #0,D0
    lea     ($0405,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z07_InitObject_NormalSpawn:
    moveq   #4,D0
    jsr     SwitchBank
    ; For monsters that spawn in a cloud, set their start time to
    ; the same value as the object slot; so that they all start
    ; moving at different times.
    ;
    moveq   #0,D2
    move.b  ($0340,A4),D2
    moveq   #0,D3
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D3
    cmpi.b  #$1E,D3
    beq  _L_z07_InitObject_FetchAttrs
    cmpi.b  #$22,D3
    beq  _L_z07_InitObject_FetchAttrs
    cmpi.b  #$53,D3
    bcc  _L_z07_InitObject_FetchAttrs
    move.b  D2,D0
    move.b  D0,($28,A4,D2.W)
    even
_L_z07_InitObject_FetchAttrs:
    ; Store the object attributes for fast access.
    ;
    lea     (ObjectTypeToAttributes).l,A0
    move.b  (A0,D3.W),D0
    lea     ($04BF,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D3,D0
    move.b  D0,($0000,A4)
    ; Hit points are packed two values to a byte.
    ; Divide the object type in half in order to index
    ; into the hit points table.
    ;
    lsr.b  #1,D0   ; LSR A
    moveq   #0,D3
    move.b  D0,D3
    lea     (ObjectTypeToHpPairs).l,A0
    move.b  (A0,D3.W),D0
    jsr     ExtractHitPointValue
    lea     ($0485,A4),A0
    move.b  D0,(A0,D2.W)
    ; If the object is a cave, go initialize it.
    ;
    move.b  ($0000,A4),D0
    cmpi.b  #$6A,D0
    bcs  _L_z07_InitObject_CheckTileObj
    moveq   #1,D0
    jsr     SwitchBank
