InitTileObjOrItem:
    ; Set object attribute to $81, and go reset metastate and timer;
    ; so that the object is ready to start updating itself.
    ;
    ; Obj attr $81 = "Custom check collision and drawing"
    ;              + "Reverse after hitting Link"
    ;
    move.b  #$81,D0
    lea     ($04BF,A4),A0
    move.b  D0,(A0,D2.W)
    beq.s  __far_z_07_0131
    jmp  ResetObjMetastateAndTimer
__far_z_07_0131:
    even
InitFluteSecret:
    ; Summary:
    ; The flute secret object manages the secret color cycle.
    ;
    ; The flute secret object is initialized in the same frame that
    ; the flute was wielded. But this object won't update until
    ; the flute timer expires.
    ;
    moveq   #1,D0
    move.b  D0,($051A,A4)
    even
ResetObjMetastateAndTimer:
    moveq   #0,D0
    move.b  D0,($28,A4,D2.W)
    even
ResetObjMetastate:
    ; Reset the object metastate so that it's ready to start
    ; behaving autonomously (updating on its own).
    ; This is the normal state outside of the spawning cloud and
    ; the death sparkle.
    ;
    moveq   #0,D0
    lea     ($0405,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
WaterPaletteTransferBufTemplate:
    dc.b    $3F, $0C, $04, $0F, $17, $37, $12, $FF

    even
PondCycleColors:
    dc.b    $12, $11, $22, $21, $31, $32, $33, $35
    dc.b    $34, $36, $37, $37

    even
UpdateFluteSecret:
    ; If secret color cycle >= $C, return.
    ;
    moveq   #0,D3
    move.b  ($051A,A4),D3
    cmpi.b  #$0C,D3
    bcs.s  __far_z_07_0132
    jmp  L1FF28_Exit
__far_z_07_0132:
    ; 7 of every 8 frames, return.
    ;
    move.b  ($0015,A4),D0
    andi.b #$07,D0
    cmpi.b  #$04,D0
    beq.s  __far_z_07_0133
    jmp  L1FF28_Exit
__far_z_07_0133:
    ; So, every 8 frames:
    ; 1. Increment the secret color cycle count.
    ; 2. Change the water palette.
    ;
    ; But when the count = $B, go reveal the stairs.
    ;
    addq.b  #1,($051A,A4)
    cmpi.b  #$0B,D3
    bne.s  __far_z_07_0134
    jmp  RevealPondStairs
__far_z_07_0134:
; Params:
; Y: a point in the cycle (0 to $B)
;
;
; Copy water palette (palette row 3) transfer buf to dynamic
; transfer buf.
    even
CueTransferPondPaletteRow:
    move.b  D3,D0
    move.b  D0,-(A5)  ; PHA
    moveq   #7,D3
    even
_L_z07_CueTransferPondPaletteRow_CopyBytes:
    lea     (WaterPaletteTransferBufTemplate).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _L_z07_CueTransferPondPaletteRow_CopyBytes
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D3
    move.b  D0,D3
    lea     (PondCycleColors).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0308,A4)
    cmpi.b  #$0A,D3
    beq.s  __far_z_07_0135
    jmp  L1FF28_Exit
__far_z_07_0135:
    move.b  #$99,D0
    move.b  D0,($034A,A4)
    even
L1FF28_Exit:
    rts

    even
RevealPondStairs:
    ; Set X and Y in this slot for the stairs in the pond.
    ; Go reveal the stairs as a secret.
    ;
    moveq   #96,D0
    move.b  D0,($70,A4,D2.W)
    move.b  #$90,D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    jmp     RevealAndFlagSecretStairsObj

    even
AnimatePond:
    ; Take turns between:
    ; * 4 frames stepping the cycle
    ; * 4 frames delaying
    move.b  ($0015,A4),D0
    andi.b #$04,D0
    bne.s  __far_z_07_0136
    jmp  L1FF28_Exit
__far_z_07_0136:
    subq.b  #1,($051A,A4)
    moveq   #0,D3
    move.b  ($051A,A4),D3
    jmp     CueTransferPondPaletteRow


