; .EXPORT IsrReset

    even
IsrReset:
    ; SEI: NES IRQ disable — NOP on Genesis (VBlank=NMI fires regardless of IRQ mask)
    ; CLD: decimal mode ignored (68000 has no decimal mode)
    moveq   #0,D0
    jsr     _ppu_write_0  ; PPU $2000 write, D0=val
    move.b  #$FF,D2
    move.b  D2,D7   ; TXS: fake SP update (D7=NES SP shadow)
_anon_z07_43:
    jsr     _ppu_read_2  ; PPU $2002 read → D0
    andi.b #$80,D0
    beq  _anon_z07_43
_anon_z07_44:
    jsr     _ppu_read_2  ; PPU $2002 read → D0
    andi.b #$80,D0
    beq  _anon_z07_44
    ori.b #$FF,D0
    jsr     _mmc1_write_8000  ; MMC1 reg write, D0=val
    jsr     _mmc1_write_a000  ; MMC1 reg write, D0=val
    jsr     _mmc1_write_c000  ; MMC1 reg write, D0=val
    jsr     _mmc1_write_e000  ; MMC1 reg write, D0=val
    moveq   #15,D0
    jsr     SetMMC1Control
    moveq   #0,D0
    jsr     _mmc1_write_a000  ; MMC1 reg write, D0=val
    lsr.b  #1,D0   ; LSR A
    jsr     _mmc1_write_a000  ; MMC1 reg write, D0=val
    lsr.b  #1,D0   ; LSR A
    jsr     _mmc1_write_a000  ; MMC1 reg write, D0=val
    lsr.b  #1,D0   ; LSR A
    jsr     _mmc1_write_a000  ; MMC1 reg write, D0=val
    lsr.b  #1,D0   ; LSR A
    jsr     _mmc1_write_a000  ; MMC1 reg write, D0=val
    moveq   #7,D0
    jsr     SwitchBank
    jmp     RunGame

    even
SetMMC1Control:
    jsr     _mmc1_write_8000  ; MMC1 reg write, D0=val
    lsr.b  #1,D0   ; LSR A
    jsr     _mmc1_write_8000  ; MMC1 reg write, D0=val
    lsr.b  #1,D0   ; LSR A
    jsr     _mmc1_write_8000  ; MMC1 reg write, D0=val
    lsr.b  #1,D0   ; LSR A
    jsr     _mmc1_write_8000  ; MMC1 reg write, D0=val
    lsr.b  #1,D0   ; LSR A
    jsr     _mmc1_write_8000  ; MMC1 reg write, D0=val
    rts

    even
SwitchBank:
    jsr     _mmc1_write_e000  ; MMC1 reg write, D0=val
    lsr.b  #1,D0   ; LSR A
    jsr     _mmc1_write_e000  ; MMC1 reg write, D0=val
    lsr.b  #1,D0   ; LSR A
    jsr     _mmc1_write_e000  ; MMC1 reg write, D0=val
    lsr.b  #1,D0   ; LSR A
    jsr     _mmc1_write_e000  ; MMC1 reg write, D0=val
    lsr.b  #1,D0   ; LSR A
    jsr     _mmc1_write_e000  ; MMC1 reg write, D0=val
    rts


; === .SEGMENT "BANK_07_VEC" ===



; Unknown block
    dc.b    $5A, $45, $4C, $44, $41, $D7, $C8, $00
    dc.b    $00, $38, $04, $01, $04, $01, $BE

    even
IsrVector:
    dc.b    $84, $E4   ; NES .ADDR (bank window, NES=$E484 = IsrNmi)
    dc.b    $43, $FF   ; NES .ADDR (bank window, NES=$FF43 = IsrReset)
    dc.b    $F0, $FF   ; NES .ADDR (bank window, NES=$FFF0 = $FFF0)

